insert into public.products
  (name, slug, description, short_description, price, compare_at_price, currency,
   images, category_id, brand_id, rating, review_count, stock_quantity, in_stock,
   is_featured, is_new, tags)
values
  ('Backstage Makeup Set Gift Set Pink', 'backstage-makeup-set-gift-set-pink', 'Online shopping for Dior. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for Dior. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Ret…', 4.81, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZBEBFA135453D9D52638BZ/45/_/1779707406/994d768b-0008-4fed-8f4f-85d390072f76.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'lips'), (select id from public.brands where slug = 'dior'), 4.2, 360, 0, true, false, true, ARRAY['makeup', 'lips', 'lip', 'glosses']::text[]),
  ('L’Oréal Paris Volume Million Lashes Panorama Mascara in Black', 'l-ore-al-paris-volume-million-lashes-panorama-mascara-in-black', 'Discover the new volumizing mascara, Panorama Mascara by Volume Million Lashes. This mascara is suitable for sensitive eyes, provides corner to corner panoramic volume, making your eyelashes look fuller and your eyes 1.4x bigger thanks to its new ultra flexible formula. Panorama Mascara is infused with 5% stretchflex complex, allowing seamless stretches while extending each lash up and out with maximum panoramic volume. The no-clump Panorama Mascara offers: - corner to corner panoramic volume for 1.4x bigger-looking eyes - 5% stretchflex complex - a panoramic mascara brush with short & long bristles to volumize & fan the eyelashes', 'Discover the new volumizing mascara, Panorama Mascara by Volume Million Lashes.', 4.33, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZEB4260E51A00F83CA67CZ/45/_/1702376384/375b6f2e-39cf-4d8f-97d1-639cc8e404dc.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZEB4260E51A00F83CA67CZ/45/_/1702376384/81d29f97-129a-4667-87ed-3953a0c71f81.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZEB4260E51A00F83CA67CZ/45/_/1702376384/916f7def-92c9-44e3-bd60-bb0f303db244.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZEB4260E51A00F83CA67CZ/45/_/1702376385/010d422a-2b12-4f65-8c0a-002d1437d6ba.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'l-oreal-paris'), 4.4, 2132, 0, true, false, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('Make-Up Fixing Spray Clear', 'make-up-fixing-spray-clear', 'Lightweight spray controls shine, creates a matte finish, and lasts all through the day. Get the maximum matte effect and enhance your makeup wear with our long-lasting setting spray. Keep your foundation, powder, eyeshadow, and brows in place for up to 16 hours. Enhance your makeup wear, control shine, and create the ultimate matte effect that will last all day', 'Lightweight spray controls shine, creates a matte finish, and lasts all through the day.', 2.89, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N46013472A/45/_/1764172155/c5a43dbf-0eaf-4c7e-b06c-9eba728751df.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'golden-rose'), 4.2, 834, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'base', 'primer', 'setting']::text[]),
  ('Lasting Finish Lipstick By Kate Moss 08 Rossetto', 'lasting-finish-lipstick-by-kate-moss-08-rossetto', 'About Brand: Rimmel is a British brand that was initially founded by House of Rimmel as a perfumery in 1834 in London, United Kingdom. It is currently a part of Coty, Inc. Coty Inc is an American multinational beauty company founded by Francois Coty. The company is engaged in developing, manufacturing, and marketing a variety of cosmetic, skincare, fragrances, hair color, and styling products. About Product: Get those celebrity-like lips with the Rimmel 08 Tender Mauve By Kate Lipstick. It bestows your lips with a subtle gleam, making them appear as two luscious petals of a fresh flower. The lipstick is enriched with moisturizing extracts to keep your lips hydrated and nourished. Its long lasting formula erases any need for frequent touch-ups. Ingredients: Ricinus Communis (Castor) Seed Oil, Candelilla Cera/euphorbia Cerifera (Candelilla) Wax/cire De Candelilla, Octyldodecanol, Caprylic/capric Triglyceride, Myristyl Lactate, Vp/Hexadecene Copolymer, Ozokerite, Lanolin, Castor Oil/ipdi Copolymer, Meadowfoam Estolide, Myristyl Myristate, Parfum/Fragrance, Silica, Benzyl Benzoate, Di-ppg-3 Myristyl Ether Adipate, Dipentaerythrityl Hexa C5-9 Acid Esters, Sorbitan Sesquioleate, Tocopherol, Propylparaben, Copernicia Cerifera Cera/Copernicia Cerifera (Carnauba) Wax/cire De Carnauba, Diamond Powder, Ascorbyl Palmitate, Benzyl Salicylate, Benzyl Cinnamate, Linalool, Aqua/water/eau, Chamomilla Recutita (Matricaria) Flower/Leaf Extract, Cucumis Sativus (Cucumber) Fruit Extract, Tin Oxide, Cinnamyl Alcohol, Eugenol. [may Contain/peut Contenir/+/-: Mica, Titanium Dioxide (Ci 77891), D&c Red No. 7 Calcium Lake (Ci 15850), D&c Red No. 6 Barium Lake (Ci 15850), Iron Oxides (Ci 77491, Ci 77492, Ci 77499), Fd&c Yellow No. 5 Aluminum Lake (Ci 19140), Fd&c Yellow No. 6 Aluminum Lake (Ci 15985), D&c Red No. 27 Aluminum Lake (Ci 45410), D&c Red No. 6 (Ci 15850), D&c Red No. 28 Aluminum Lake (Ci 45410), D&c Red No. 33 Aluminum Lake (Ci 17200), Fd&c Blue No. 1 Aluminum Lake (Ci 42090) and Carmine (Ci 75470)]', 'About Brand: Rimmel is a British brand that was initially founded by House of Rimmel as a perfumery in 1834 in London, United Kingdom.', 2.4, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N11034765A/45/_/1764236084/82c5eba7-a5d7-4deb-8174-00bac1927867.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11034765A/45/_/1764236084/d5d455a5-3e5a-4dc4-b84b-f2d6b6463222.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11034765A/45/_/1764236085/1715fe3a-ed36-47b4-ac29-bb8f6d5ed219.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11034765A/45/_/1764236002/05e69c28-82a1-4efc-bf8f-531b07aa29b5.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'lips'), (select id from public.brands where slug = 'rimmel-london'), 4.2, 1772, 0, true, false, true, ARRAY['makeup', 'lips', 'lipstick']::text[]),
  ('Micellar Water Face Cleanser And Daily Makeup Remover Clear', 'micellar-water-face-cleanser-and-daily-makeup-remover-clear', 'GARNIER NUMBER 1 MICELLAR BRAND WORLDWIDE* The All-in-one solution for all skin types, including sensitive skin. Suitable for face, eyes, and lips. MAKEUP REMOVER + CLEANSER. Soothes with one cotton pad. Garnier Introduces the MICELLAR technology. It is formulated with micelles which capture dirt, sebum, solution and everyday make-up from your skin like magnets in one gesture. Dermatologically and ophthalmologically tested. The result: Skin is perfectly cleansed, soothed and refreshed. How to use 1. Pour some micellar drops on a cotton pad. 2. Press lightly for a few seconds onto the face, eyes and lips without rubbing. 3. Press gently on skin, eyes and lips. 4. Perfectly cleansed and soothed skin without the need for rinsing.', 'GARNIER NUMBER 1 MICELLAR BRAND WORLDWIDE* The All-in-one solution for all skin types, including sensitive skin.', 3.52, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N11294362A/45/_/1770374400/38889d8e-0cc8-49a3-8c2f-f0fee4e0d8f1.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11294362A/45/_/1751379407/e3a96c8b-5f73-4fe4-97e0-9ce79f10eff2.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11294362A/45/_/1751379405/c3b045a3-4437-46d9-ad38-ff32d02b0f13.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11294362A/45/_/1751379408/8e007355-cdb2-4634-9f67-d03dbd05451e.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'makeup-remover'), (select id from public.brands where slug = 'garnier'), 4.5, 8286, 0, true, false, true, ARRAY['makeup', 'remover']::text[]),
  ('Set of four multi-sized makeup bags - Z40', 'set-of-four-multi-sized-makeup-bags-z40', 'These makeup bags will be your favorite companion for every outing or trip. They combine functionality with a lovely appearance. The set includes four bags in different sizes , perfect for organizing makeup, skincare products, or even using them as inner pouches in your travel luggage. They are padded, lightweight, and protect your items from breaking or damage. What makes them even more special is the cute bow that adds an elegant, girly touch. How to Use: Sort your items by size and choose the appropriate bag for each purpose. Whether you’re using it for brushes, skincare, or hair accessories—there’s a size that fits every need. Tips Before Use: Avoid placing uncovered sharp objects inside to protect the padded fabric. Use the smaller pouches for daily essentials and the larger ones for travel or long-term storage. Clean with a soft, damp cloth. Frequently Asked Questions: Are the bags waterproof? They are padded but not fully waterproof. It’s best to keep them away from heavy moisture. Can children use them? Absolutely! They are beautifully designed and suitable for all ages. Girls especially will love them. Product Story: We designed this set for girls who love staying organized and want something stylish and practical at the same time. The four different pieces are all you need to keep things in place wherever you go—no clutter, just order and elegance. Trenz Story: In a world full of options, Trenz stands out as a proud Saudi brand dedicated to offering beauty and wellness products that meet the needs of today’s modern woman. Founded with a clear vision and a noble goal, Trenz empowers women to feel confident and beautiful every day with innovative, high-quality products. Our diverse range includes makeup brushes, beauty sponges, mirrors, nail files, and more. Every item is the result of careful research and attention to detail—to bring you the very best. Trenz is not just a brand; it''s your everyday companion on your journey to beauty and self-care. Join us and discover how our products can add a touch of elegance and comfort to your life. Keywords: makeup bags, cosmetic bag,', 'These makeup bags will be your favorite companion for every outing or trip. They combine functionality with a lovely appearance.', 5.99, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z8B561DE15CDB81AA9BF9Z/45/1752676014/4fced0bd-0194-4587-99ab-400ac07e274f.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8B561DE15CDB81AA9BF9Z/45/1752675921/5fd98666-742a-42c2-b88d-a93d2654acb3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8B561DE15CDB81AA9BF9Z/45/1752676028/623cb7cd-276c-4484-a83a-bd0eb43f1b48.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8B561DE15CDB81AA9BF9Z/45/1762190656/8cc311b5-458e-43be-ac57-41f9ca478af5.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'makeup-tools-accessories'), (select id from public.brands where slug = 'trenz'), 4.7, 86, 0, true, false, true, ARRAY['makeup', 'tools', 'accessories', 'cosmetic', 'toiletry', 'bags']::text[]),
  ('Nail Glue', 'nail-glue', 'Provides an easy to use brush on applicator for strong, permanent nail repairs for effective nail tip application. Bonds quickly and easily', 'Provides an easy to use brush on applicator for strong, permanent nail repairs for effective nail tip application.', 1.495, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z4EC139158421598A8768Z/45/_/1780752992/1c6a47b6-4258-4229-93f9-59dfa814d2a5.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'nail-makeup'), (select id from public.brands where slug = 'real-beauty'), 4.4, 218, 0, true, false, true, ARRAY['makeup', 'nail', 'false', 'nails', 'accessories', 'glue']::text[]),
  ('Fit Me Concealer Anti-Cernes Medium 25', 'fit-me-concealer-anti-cernes-medium-25', 'Fit Me® Concealer makeup for flawless, natural coverage. These oil-free concealers match skin tones to deliver a more even complexion. Skin looks perfected with this natural coverage liquid concealer. These oil-free concealers conceal redness, flaws, and blemishes. Shades of concealers for various skin tones. Dermatologist tested. Ophthalmologist tested. Non-comedogenic concealer. Fragrance-free. Packaging may vary, what you receive may not be what is reflected on site. How to use: Step 1. Dot concealer onto imperfections or under the eyes. Step 2. Pat with a finger to blend.', 'Fit Me® Concealer makeup for flawless, natural coverage. These oil-free concealers match skin tones to deliver a more even complexion.', 2.08, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N11031274A/45/_/1774425302/60dc93d8-1ad8-41c2-af4b-fd08c5bc7033.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11031274A/45/_/1764236041/ca50e00d-d868-4d0b-9af2-746ab83632fb.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11031274A/45/_/1764236038/42254159-a2e3-4e6b-9eb3-0e4e76a5dabf.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11031274A/45/_/1764236039/84720e08-4a25-4946-a37f-f5d77e5005a8.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'maybelline-new-york'), 4.4, 2708, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'concealers', 'correctors']::text[]),
  ('TRENZ Professional Makeup Brush Set 8 Pcs with Case — Soft Non-Shedding Fibers for Foundation, Contour & Eyes, Black- S05', 'trenz-professional-makeup-brush-set-8-pcs-with-case-soft-non-shedding', 'Looking for a professional touch and everyday elegance at the same time? The TRENZ makeup brush set gives you everything you need for a daily look or a special occasion. Whether you want to contour your cheeks, blend foundation, or define your eyes, these 8 thoughtfully shaped brushes suit both practical use and modern beauty — and they come with a sleek case that keeps them all organized in one place. FAQ Q: Do the bristles shed during use? A: The brushes use durable, non-shedding fibers made for long-term use. For best bristle retention, avoid pulling, clean them gently, and let them dry flat. Q: Is the set good for beginners? A: Yes — the 8 brushes cover every basic step (foundation, concealer, contour, eyeshadow, detailing), so you can do a full face easily even as a beginner. Q: How many brushes are included, and is there a case? A: The set includes 8 brushes plus a sleek case that organizes and protects them and makes them easy to carry while traveling. Q: Are the bristles soft on the skin? A: Yes, the silky bristles glide gently over the skin and help apply product evenly without scratching. Q: Does it make a good gift? A: Absolutely — the elegant design and organizing case make it an ideal gift, available in black or multi-color. Brand Story In a world full of choices, TRENZ stands out as a distinguished Saudi brand dedicated to beauty and wellness products for the modern woman — empowering women to feel confident and beautiful every day through innovative, high-quality products. TRENZ — Confidence in Every Touch keywords: makeup brushes makeup brush set cosmetic brushes foundation brush blending brush', 'Looking for a professional touch and everyday elegance at the same time? The TRENZ makeup brush set gives you everything you need for a dail…', 4.25, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZD04630C8DDB9D1213B52Z/45/1765392140/6da73f3f-aa98-444b-9827-8762b8079f29.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD04630C8DDB9D1213B52Z/45/1748090118/5930533a-314a-4a60-8c62-4f3b2aad2145.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD04630C8DDB9D1213B52Z/45/1748090129/addde825-9534-499f-a982-1d446fe7079a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD04630C8DDB9D1213B52Z/45/1748091034/9a6bb8a8-4400-4a42-9b55-d61c9abb6def.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'makeup-tools-accessories'), (select id from public.brands where slug = 'trenz'), 4.5, 100, 0, true, false, true, ARRAY['makeup', 'tools', 'accessories', 'brush', 'sets']::text[]),
  ('I Love Extreme Black Mascara Crazy Volume', 'i-love-extreme-black-mascara-crazy-volume', 'About the product: For all fans of one stroke volume, this mascara will hit the spot! The large fiber brush quickly adds incredible volume to each lash and it is opthalmologically tested. About the brand: Essence was started by Christina, a fearless entrepreneurial woman, who wanted to make a different cosmetics brand &ndash; a really fun brand that offers both great quality and excellent prices. Ingredients: Aqua (Water), Carnauba (Copernicia Cerifera) Wax, Cera Alba (Beeswax), Butylene Glycol, Stearic Acid, VP/Eicosene Copolymer, Palmitic Acid, Polybutene, Glyceryl Stearate, Acacia Senegal Gum, Candelilla (Euphorbia Cerifera) Wax, PVP, Caprylyl Glycol, Polyvinyl Alcohol, Aminomethyl Propanol, Sodium Dehydroacetate, Phenoxyethanol, CI 77499 (Iron Oxides). How to use: Starting at the base of the lash line, wiggle wand back and forth, adding as many coats as you like until desired length and volume is achieved.', 'For all fans of one stroke volume, this mascara will hit the spot! The large fiber brush quickly adds incredible volume to each lash and it…', 1.26, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z93D2BF8823369CCEB016Z/45/_/1779343777/d974c1df-6fa4-43f0-bdfb-7b85fe52202f.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z93D2BF8823369CCEB016Z/45/_/1779343777/0ad11ff8-9f61-478d-8f45-84b7d4faa12c.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z93D2BF8823369CCEB016Z/45/_/1779343777/cc2c57cc-a574-43b5-9c90-40c76c8ff6ad.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z93D2BF8823369CCEB016Z/45/_/1779343777/b004f99e-ecd3-4c9f-8a16-f0f1328f531c.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'essence'), 4.4, 6110, 0, true, false, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('Waterproof Lipliner Pencil 244 Chocolate Fondue', 'waterproof-lipliner-pencil-244-chocolate-fondue', 'Filling spheres reduce wrinkles and add volume. Richly pigmented to give intense colour and matte finish. Velvety texture glides on smoothly and blends in seamlessly', 'Filling spheres reduce wrinkles and add volume. Richly pigmented to give intense colour and matte finish.', 1.9, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZA64D4FB6C150B4CA01A4Z/45/_/1779873952/2d927088-2687-4619-bc8c-37a87d23352f.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZA64D4FB6C150B4CA01A4Z/45/_/1779873951/df3c700a-a88c-4ff1-b513-36b250b68242.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'lips'), (select id from public.brands where slug = 'flormar'), 4.3, 1962, 0, true, false, true, ARRAY['makeup', 'lips', 'lip', 'liners']::text[]),
  ('Brows On Demand 2-In-1 Brow Pencil Espresso', 'brows-on-demand-2-in-1-brow-pencil-espresso', 'Up Your Brow Game From Every Angle With Our Double-Ended Eyebrow Pencil. One Side Features A Waterproof Matte Cream Tip That''S Designed Extra Skinny For Precise Lines That Mimic Your Natural Hairs. The Other End Offers A Luxe Liquid That''S Waterproof, Sweat-Proof & Oil-Resistant, And Infused With Multiple Pigments For A Well-Rounded Shade. And What''S Even More Magical? This Baby Is Built For All Brow Types And Skin Tones Because In Our World, Everyone Deserves Bomb Brows!', 'Up Your Brow Game From Every Angle With Our Double-Ended Eyebrow Pencil.', 1.36, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z69035836F66952DE8F39Z/45/_/1779094915/b609e545-c348-46c4-a751-5a297884d077.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z69035836F66952DE8F39Z/45/_/1779094915/2ec4a82a-d064-4d5d-9e9f-01890dc6a1a5.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z69035836F66952DE8F39Z/45/_/1779094915/30ed6ebe-c4e4-4db3-bb90-71b161601bff.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z69035836F66952DE8F39Z/45/_/1779094915/6013df85-adfe-4412-82c3-7eb0888c6901.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'sheglam'), 4.5, 886, 0, true, false, true, ARRAY['makeup', 'eyes', 'eyebrow', 'pencils']::text[]),
  ('Lash Princess Volume False Effect Mascara Black', 'lash-princess-volume-false-effect-mascara-black', 'About the product: The original lash princess has a big and bold sister with voluminous false lash effects! The conic shape fiber brush provides lashes with dramatic volume and sculpted length, just like false lashes without all the fuss. About the brand: Essence was started by Christina, a fearless entrepreneurial woman, who wanted to make a different cosmetics brand – a really fun brand that offers both great quality and excellent prices. Ingredients: Aqua (Water), Paraffin, Glyceryl Stearate, Synthetic Beeswax, Stearic Acid, Acacia Senegal Gum , Butylene Glycol, Palmitic Acid, Polybutene, Oryza Sativa (Rice) Bran Wax, Vp/Eicosene Copolymer, Ozokerite, Aminomethyl Propanol, Tropolone, Hydrogenated Vegetable Oil, Stearyl Stearate, Hydroxyethylcellulose, Phenoxyethanol, CI 77499 (Iron Oxides). How to use: Starting at the base of the lash line, wiggle wand back and forth, adding as many coats as you like until desired length and volume is achieved.', 'The original lash princess has a big and bold sister with voluminous false lash effects! The conic shape fiber brush provides lashes with dr…', 1.53, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z809D069EA901B6502078Z/45/_/1779345604/2c6efa2b-b2de-43f1-a6cf-7ebc3bead95b.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z809D069EA901B6502078Z/45/_/1779345604/362f1072-21db-4550-96fd-c8c5fec4a855.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z809D069EA901B6502078Z/45/_/1779345604/76e08324-6c22-4fad-b149-64db42dc4bc6.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z809D069EA901B6502078Z/45/_/1779345604/d67d336f-7a92-4365-9085-1e505a9bd926.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'essence'), 4.1, 17810, 0, true, false, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('White Shell - Tanning Oil - 200ml', 'white-shell-tanning-oil-200ml', 'Online shopping for white shell. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for white shell. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy F…', 12.45, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z9FFD340F52B826A89036Z/45/1762936757/6ee61065-2508-4110-9adc-138ca808282a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z9FFD340F52B826A89036Z/45/1762936551/1e49964b-4ca1-4141-bbc9-1631d580f3d0.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z9FFD340F52B826A89036Z/45/1762936551/ed093511-3fad-4781-9e98-0e3c8024adcd.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z9FFD340F52B826A89036Z/45/1762936551/0135606e-a5f5-40ed-8c24-e10827b91a30.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'sun-care'), (select id from public.brands where slug = 'white-shell'), 0, 0, 0, true, false, true, ARRAY['skin', 'care', 'sun', 'self', 'tanners', 'bronzers']::text[]),
  ('MISS ROSE DUSTING POWDER FOR THE BODY', 'miss-rose-dusting-powder-for-the-body', 'Online shopping for Miss Rose. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for Miss Rose. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Fre…', 3.3, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZF015C5A672916CD24ECEZ/45/_/1735395594/ed0d3522-4b36-43fc-818d-ab6a7dd1cebb.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZF015C5A672916CD24ECEZ/45/_/1735395595/2ed3ed9c-d440-49e0-9653-4e6e0000e246.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZF015C5A672916CD24ECEZ/45/_/1733856545/e177b2d2-8068-4506-82b8-4c0d0b6eaf01.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'body-talcum-powders'), (select id from public.brands where slug = 'miss-rose'), 3.9, 9, 0, true, false, true, ARRAY['skin', 'care', 'body', 'talcum', 'powders']::text[]),
  ('Whitening And Fade Spots Skin Care Set Of 4 Pieces Night Cream Day Cream Lightening Lotion Whitening Serum 50+50+50+80grams', 'whitening-and-fade-spots-skin-care-set-of-4-pieces-night-cream-day-cre', 'Night cream to remove dark spots and whiten the skin, 50 grams. Skin lightening and purifying lotion 80 grams. Whitening and moisturizing day cream 50 grams. Whitening and stain remover serum 50 ml', 'Night cream to remove dark spots and whiten the skin, 50 grams. Skin lightening and purifying lotion 80 grams.', 5.5, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZE679FD79A5BE386E9B91Z/45/_/1778592347/9baf3682-e90e-42f1-8eb3-6fd62c4b5f6e.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE679FD79A5BE386E9B91Z/45/_/1778592347/2d7e9c51-9c3e-4cf2-95ac-bfdabd213d42.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'creams-moisturizers'), (select id from public.brands where slug = 'dr-rashel'), 4.2, 21, 0, true, false, true, ARRAY['skin', 'care', 'creams', 'moisturizers', 'anti', 'ageing']::text[]),
  ('Moisturising Cream For Dry To Very Dry And Sensitive Skin White 550grams', 'moisturising-cream-for-dry-to-very-dry-and-sensitive-skin-white-550gra', 'Ingredients: Purified Water, Polyglycerylmethacrylate (and) Propylene Glycol, Petrolatum, Dicaprylyl Ether, PEG-5 Glyceryl Stearate, Glycerin, Dimethicone and Dimethiconol, Cetyl Alcohol, Sweet Almond Oil, Acrylates/C10-30 Alkyl Acrylate Crosspolymer, Tocopheryl Acetate, Phenoxyethanol, Benzyl Alcohol, Disodium EDTA, Sodium Hydroxide, Lactic Acid. Apply liberally as often as needed. Cetaphil Moisturizing Cream contains a superior system of extra-strength emollients and humectants clinically proven to bind water to the skin and prevent moisture loss. The result is long-lasting relief for even severely dry skin. The non-greasy formula is excellent for hands, feet, elbows, knees, and any other areas that require intensive moisturization. About the product: Cetaphil moisturizing cream and moisturizing lotion double the moisture of the skin in just four days with moisture that lasts. Data on file, galderma australia pty ltd. The cetaphil moisturisers have a unique combination of quality ingredients: emollients are the essential first stage to soften the skin. Humectants then draw up the naturally occurring moisture from deep within the skin. About the brand: Cetaphil is a skincare brand that is recommended by dermatologists, and is today used by millions of people with sensitive skin from all over the world. The original product, Cetaphil Cleansing Lotion, was invented by a pharmacist in 1947 specifically for dermatological needs. Ingredients: Water, Glycerin, Petrolatum, Dicaprylyl Ether, Dimethicone, Glyceryl Stearate, Cetyl Alcohol, Helianthus Annuus (Sunflower) Seed Oil, PEG-30 Stearate, Tocopheryl Acetate (Vitamin E), Dimethiconol, Acrylates/C10-30 Alkyl Acrylate Crosspolymer, Benzyl Alcohol, Phenoxyethanol, Prunus Amygdalus Dulcis (Sweet Almond) Oil, Propylene Glycol, Disodium EDTA, Carbomer, Sodium Hydroxide.', 'Ingredients: Purified Water, Polyglycerylmethacrylate (and) Propylene Glycol, Petrolatum, Dicaprylyl Ether, PEG-5 Glyceryl Stearate, Glyceri…', 4, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZAC97FE126018CADE1111Z/45/_/1779179151/bd8f149e-2235-43ba-9aaa-b44db7ab2b21.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZAC97FE126018CADE1111Z/45/_/1779179151/80b1b6c4-1b5b-42be-ab50-8a59723bc784.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZAC97FE126018CADE1111Z/45/_/1779179151/f961aa11-7c21-4058-b0e9-0a0dfc891a7d.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZAC97FE126018CADE1111Z/45/_/1779179151/f3046870-6bfa-4633-a8e1-106c7ccbe6a7.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'creams-moisturizers'), (select id from public.brands where slug = 'cetaphil'), 3.1, 8199, 0, true, false, true, ARRAY['skin', 'care', 'creams', 'moisturizers', 'face']::text[]),
  ('Niacinamide 10% And Zinc 1% Clear 30ml', 'niacinamide-10-and-zinc-1-clear-30ml', 'About the product: Niacinamide (Vitamin B3) is indicated to reduce the appearance of skin blemishes and congestion. A high 10% concentration of this vitamin is supported in the formula by zinc salt of pyrrolidone carboxylic acid to balance visible aspects of sebum activity. Contraindications: If topical Vitamin C (L-Ascorbic Acid and/or Ethylated L-Ascorbic Acid) is used as part of skincare, it should be applied at alternate times with this formula (ideally Vitamin C in the PM and this formula in the AM). Otherwise, Niacinamide can affect integrity of the Vitamin About the brand: The Ordinary is an evolving collection of treatments offering familiar, effective clinical technologies positioned to raise pricing and communication integrity in skincare. The brand was created to celebrate integrity in its most humble and true form. Its offering is pioneering, not in the familiar technologies it uses, but in its honesty and integrity. The Ordinary is born to disallow commodity to be disguised as ingenuity. The Ordinary is "Clinical formulations with integrity". Ingredients: Water, Niacinamide, Pentylene Glycol, Zinc PCA, Tamarindus Indica Seed Gum, Xanthan Gum, Isoceteth-20, Ethoxydiglycol, Phenoxyethanol, Chlorphenesin. How to use: Apply a few drops to entire face in morning and evening before heavier creams. Precautions: If topical vitamin C is used as part of skincare, it should be applied at alternate times with this formula in the AM. Otherwise, niacinamide can affect integrity of pure-form vitamin C.', 'Niacinamide (Vitamin B3) is indicated to reduce the appearance of skin blemishes and congestion.', 3.1, NULL, 'BHD', '["https://f.nooncdn.com/p/fb889ec50f784103a85817c4c97eadd1|pzsku/Z98B89E90ACD02256C23AZ/45/1771237421/787b07ba-d575-4e2b-8041-08825577b4bc.jpg?width=1200","https://f.nooncdn.com/p/fb889ec50f784103a85817c4c97eadd1|pzsku/Z98B89E90ACD02256C23AZ/45/1771237421/0fdf1326-921d-4541-80f8-4ef83f36530c.jpg?width=1200","https://f.nooncdn.com/p/fb889ec50f784103a85817c4c97eadd1|pzsku/Z98B89E90ACD02256C23AZ/45/1771237421/b2f4ac88-8402-4d01-ae9a-00e8b0bab3ec.jpg?width=1200","https://f.nooncdn.com/p/fb889ec50f784103a85817c4c97eadd1|pzsku/Z98B89E90ACD02256C23AZ/45/1771237421/c0167f22-a042-4703-b595-6a1bf66c3eab.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'treatment-serums'), (select id from public.brands where slug = 'the-ordinary'), 4, 6317, 0, true, false, true, ARRAY['skin', 'care', 'treatment', 'serums', 'face']::text[]),
  ('Effaclar Purifying Foaming Gel 200Ml Cleanser; Acne Face Wash For Women/Men; Dermatologically-Tested Skincare Treatment For Oily & Sensitive Skin 200ml', 'effaclar-purifying-foaming-gel-200ml-cleanser-acne-face-wash-for-women', 'La Roche Posay Effaclar Gel gently purifies oily skin without drying effects thanks to gentle cleansing agents rigorously selected to ensure good tolerance. It removes impurities and excess sebum, leaving the skin clean and refreshed. With anti-irritant La Roche-Posay thermal spring water and with Zinc to reduce sebum. Cleansing agents are selected for their high-efficacy action in eliminating impurities and excess sebum. The Effaclar Gel is specifically adapted and well-tolerated cleansing for acne-prone skin. Physiological pH - Alcohol-free.Non-comedogenic. Tested on acne-prone skin.', 'La Roche Posay Effaclar Gel gently purifies oily skin without drying effects thanks to gentle cleansing agents rigorously selected to ensure…', 6.895, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N11294411A/45/_/1776342617/8aa01818-748b-4d72-ad89-d85b6b90811c.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11294411A/45/_/1776342618/3e5db9ae-6275-4023-9a94-afb060e70ea3.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11294411A/45/_/1776342619/9b8a5389-43b4-4257-ab52-dea536eed03b.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11294411A/45/_/1776342619/4579137c-83db-431e-b8d4-1dbe279845bc.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'skin-cleansers'), (select id from public.brands where slug = 'la-roche-posay'), 0, 0, 0, true, false, true, ARRAY['skin', 'care', 'cleansers', 'face', 'wash']::text[]),
  ('Dr.Althea 345 Relief Cream - Soothing Face Moisturizer with Niacinamide & Panthenol | Blemish Care, Hydration & Redness Relief | Vegan Korean Skincare for All Skin Types | 50ml', 'dr-althea-345-relief-cream-soothing-face-moisturizer-with-niacinamide', 'BLEMISH RELIEF INGREDIENTS : This cream contains a potent blend of Niacinamide and plant extracts to reduce dark spots and blemishes. It also promotes an even skin tone, assisting you in achieving clearer and more radiant skin.. NOURISHING INGREDIENTS : The multi-layered cream structure formulated with Ceramide NP and Hyaluronic acids help restore dull skin while delivering nutrients deeply into the skin to provide continuous care by locking in moisture and nutrients.. SOOTHING INGREDIENTS : Care for sensitive skin and red blemishes caused by external factors with Beta-glucan, Panthenol, and Plant extracts. These calming ingredients can quickly help soothe your skin effectively by providing moisture.. DAILY RELIEF & SOOTHING CARE : 345 Relief Cream offers a moisturizing texture with a silky finish without any greasy feeling. Its refreshing formula is ideal for any time as part of your post-acne skincare routine.', 'BLEMISH RELIEF INGREDIENTS : This cream contains a potent blend of Niacinamide and plant extracts to reduce dark spots and blemishes.', 2.995, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z699AD3C77DB066ACC139Z/45/_/1782800506/19c3c646-cde4-4b36-9d1d-bb59dba46065.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z699AD3C77DB066ACC139Z/45/_/1782800527/f0e9e810-4740-49c7-b821-e53a3a97c8fe.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z699AD3C77DB066ACC139Z/45/_/1782800527/7ab8e552-f2d0-4480-8f86-5110df015382.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z699AD3C77DB066ACC139Z/45/_/1782800527/01c6030d-7a9b-42fc-897c-eeb1798181dd.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'treatment-serums'), (select id from public.brands where slug = 'dr-althea'), 4.1, 51, 0, true, false, true, ARRAY['skin', 'care', 'treatment', 'serums', 'acne', 'blemish']::text[]),
  ('Uv Defender Invisible Fluid Sunscreen Spf 50+ Pa++++ 50 Ml', 'uv-defender-invisible-fluid-sunscreen-spf-50-pa-50-ml', 'In your daily environment, uv rays are the major contributors to premature skin aging signs. Uv defender invisible fluid daily anti aging sunscreen advanced uv protection: daily broad spectrum filtering system to provide very high sun protection with spf 50+ and long uva to protect skin from aging signs induced by uv, such as: dark spots, dullness and fine lines. Invisible fluid: this non greasy, fast absorbing ultra light texture results in an invisible skin finish that is formulated with a netlock technology, formulated by l''oreal laboratories. It leaves a clean touch without white residues and forms a protective layer on the skin. Multi resistance: the fluid provides a homogeneous protection offering a high resistance to water and friction, while reducing pollution particles adhesion. Results: immediately, skin is protected from uv rays and photoaging signs:fine lines, dark spots and dull skin. Day after day, skin looks more smooth, radiant with more refined texture. Usage: shake well before use. Apply on top of your moisturizer. Glides on easily without a ecting makeup.', 'In your daily environment, uv rays are the major contributors to premature skin aging signs.', 3.4, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZDB3C98DEA56A9778EB1CZ/45/1746946457/21fcd0be-3123-49a4-a265-246549d09281.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'sun-care'), (select id from public.brands where slug = 'l-oreal-paris'), 4.4, 80, 0, true, false, true, ARRAY['skin', 'care', 'sun', 'sunscreen']::text[]),
  ('Moisturising Cream 50ml', 'moisturising-cream-50ml', 'A protective moisturising body cream. All day hydration for dry skin. Specifically formulated to moisturise sensitive skin that is dry. Also suitable to use on eczema-prone skin. Moisturises the protective skin barrier of the face and body. With 3 naturally occurring ceramides and Hyaluronic Acid which are essential in supporting the skin barrier and retaining moisture. Utilises patented MVE delivery technology to help replenish ceramides and deliver controlled, long lasting hydration. How to use Apply to the face and body, as often as needed FREE Delivery', 'A protective moisturising body cream. All day hydration for dry skin. Specifically formulated to moisturise sensitive skin that is dry.', 1.837, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z506E2A14BF68D10F97DDZ/45/_/1778231405/1849ac30-d8f4-4bff-95fc-6b175034f9f9.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z506E2A14BF68D10F97DDZ/45/_/1778231405/8822039d-7acb-4be4-baad-2efd542bcdf6.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z506E2A14BF68D10F97DDZ/45/_/1778231405/33c12abf-fc78-4365-bc56-66b80d2f2a0b.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z506E2A14BF68D10F97DDZ/45/_/1778231405/e15b8ab8-ee85-4241-84a2-4f4214a64632.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'creams-moisturizers'), (select id from public.brands where slug = 'cerave'), 4.4, 5875, 0, true, false, true, ARRAY['skin', 'care', 'creams', 'moisturizers', 'face']::text[]),
  ('Relief Sun: Rice + Probiotics 50ml | SPF 50 50ml', 'relief-sun-rice-probiotics-50ml-spf-50-50ml', 'Relief Sun is a lightweight and creamy type organic sunscreen that''s comfortable on skin. Even if you apply a large amount several times, it is not sticky and gives a moist finish like that of a light moisturizing cream. Containing 30% rice extract and grain fermented extracts, it provides moisture and nourishment to the skin.', 'Relief Sun is a lightweight and creamy type organic sunscreen that''s comfortable on skin.', 4.175, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z6536870E2C22EBE42454Z/45/_/1783585226/9fbb1cb9-aa24-45c2-82a3-82a89f2a37cc.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6536870E2C22EBE42454Z/45/_/1783585226/c91703aa-12dc-4935-acae-d22184004c90.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6536870E2C22EBE42454Z/45/_/1783585226/20331aa6-ba7b-425a-a983-d6474d030f40.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6536870E2C22EBE42454Z/45/_/1783585226/aa4d1636-1251-4b0d-9b02-feaf23e31c8b.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'sun-care'), (select id from public.brands where slug = 'beauty-of-joseon'), 4.1, 5683, 0, true, false, true, ARRAY['skin', 'care', 'sun', 'sunscreen']::text[]),
  ('Hydrating Cleanser For Normal To Dry Skin With Hyaluronic Acid 236ml', 'hydrating-cleanser-for-normal-to-dry-skin-with-hyaluronic-acid-236ml', 'CeraVe Hydrating Facial Cleanser is a gentle face wash with ingredients like ceramides and hyaluronic acid that work to restore the skin''s natural barrier to help the skin lock in moisture. CeraVe Hydrating Cleanser was designed to cleanse and refresh the skin without over-stripping it or leaving it feeling tight and dry. Featuring three essential ceramides to restore the skin''s barrier, hyaluronic acid to hydrate the skin, and MVE Delivery Technology to supply the skin with a steady stream of nourishment, this non-comedogenic face wash is an effective yet non-irritating way to start off any skincare regimen. Best for normal to dry skin. Usage for Men and Women. Fragrance-free, suitable for children 3 years & older.', 'CeraVe Hydrating Facial Cleanser is a gentle face wash with ingredients like ceramides and hyaluronic acid that work to restore the skin''s n…', 3.795, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z5762814BD5CB3E5D7FCBZ/45/_/1779179333/9ad8637d-97c6-4d4d-8862-9b0d23b5c0c6.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z5762814BD5CB3E5D7FCBZ/45/_/1779179333/674e9f98-5f35-49cb-bf9f-c3ad28f1cf64.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z5762814BD5CB3E5D7FCBZ/45/_/1779179333/3466b1e4-6b1f-4e92-bd4c-f0549585d11e.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z5762814BD5CB3E5D7FCBZ/45/_/1779179333/a842b91c-9e1b-45bd-9c9a-acfcb0a8761c.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'skin-cleansers'), (select id from public.brands where slug = 'cerave'), 4.4, 4532, 0, true, false, true, ARRAY['skin', 'care', 'cleansers', 'face', 'wash']::text[]),
  ('Cicaplast Baume B5+ Ultra Repairing Multi-Purpose Moisturizer Soothing and Reapairing Balm – for dry, damanged, irritiated and sensitive skin for whole family, including babies.', 'cicaplast-baume-b5-ultra-repairing-multi-purpose-moisturizer-soothing', 'La Roche-Posay Cicaplast Baume B5+ is a multi-purpose repairing balm that soothes and protects the whole family’s sensitive or irritated skin. Suitable for adults, children and babies, it can be used on all kinds of everyday skin irritations and minor injuries and is ideal for use on sensitive skin.', 'La Roche-Posay Cicaplast Baume B5+ is a multi-purpose repairing balm that soothes and protects the whole family’s sensitive or irritated ski…', 5.595, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z14F066B82CEDBAA0BB96Z/45/_/1778155572/ddf143de-6eff-4a05-a5d8-0b8cb27e6292.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z14F066B82CEDBAA0BB96Z/45/_/1778155572/204abbbf-92f0-44e9-9025-483919d22476.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z14F066B82CEDBAA0BB96Z/45/_/1778155573/fc61b0fc-c955-409e-b937-df63d23054b4.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z14F066B82CEDBAA0BB96Z/45/_/1778155573/6e1b4bff-2943-4675-9f87-c011ba9a574b.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'creams-moisturizers'), (select id from public.brands where slug = 'la-roche-posay'), 4.5, 5952, 0, true, false, true, ARRAY['skin', 'care', 'creams', 'moisturizers', 'face']::text[]),
  ('Foaming Cleanser For Normal To Oily Skin With Hyaluronic Acid 236ml', 'foaming-cleanser-for-normal-to-oily-skin-with-hyaluronic-acid-236ml', 'CeraVe Foaming Facial Cleanser was developed with dermatologists to deeply cleanse, remove excess oil and refresh the skin without over-stripping it or leaving it feeling tight and dry. Featuring three essential ceramides, hyaluronic acid and niacinamide, this gel-based foaming cleanser is an effective yet non-irritating way to cleanse and care for your normal to oily skin. A foaming facial cleanser is ideal for removing excess oil, dirt and makeup—and choosing one that''s gentle, won’t disrupt your skin’s natural protective barrier and contains ingredients that help maintain moisture balance can make all the difference. CeraVe Foaming Facial Cleanser features ceramides, hyaluronic acid and niacinamide to help restore the skin’s barrier, attract hydration and calm the skin. Usage for Men and Women.', 'CeraVe Foaming Facial Cleanser was developed with dermatologists to deeply cleanse, remove excess oil and refresh the skin without over-stri…', 4.895, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZD484FFE6AB5D3BFF7062Z/45/_/1779179214/a92570c4-0320-4ccf-b28e-36d4ff00ccd2.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD484FFE6AB5D3BFF7062Z/45/_/1779179214/718ab0c0-2635-4c78-9db2-c182f88f09da.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD484FFE6AB5D3BFF7062Z/45/_/1779179214/ae75df8f-a7a6-4b9a-8d35-a3b223cb484d.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD484FFE6AB5D3BFF7062Z/45/_/1779179214/01c484d5-9ecf-4166-8e49-dfbd778f29ef.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'skin-cleansers'), (select id from public.brands where slug = 'cerave'), 4.5, 7129, 0, true, false, true, ARRAY['skin', 'care', 'cleansers', 'face', 'wash']::text[]),
  ('Panthederm Moisturizing Cream For Dry To Very Dry Skin and Sensitive Skin with D.Panthenol + Shea Butter+ Vitamin E + 8 Natural Oils 50 ml', 'panthederm-moisturizing-cream-for-dry-to-very-dry-skin-and-sensitive-s', 'Panthederm moisturizing cream for dry skin and Eczema (50 ml) Moisturizing cream for dry skin and very dry skin that may be prone to eczema. Provides deep and effective hydration thanks to 8 oils and other moisturizing agents. Hydration lasts for a longer duration due to moisture loss blockers that act as a shield for the skin against harsh climatic conditions. Reduces inflammation and redness with its soothing formula, thereby alleviating itching. Provides superior and special care for eczema sufferers. A non-greasy texture that is easy to spread, featuring a fragrance- and silicone-free formula. Active Ingredients : Dexa Panthenol Vitamin E Olive Oil Shea Butter Coconut Oil Argan Oil Moringa Oil Jojoba Oil Aloe Vera Extract Chamomile Extract Sesame Oil Sweet Almond Oil', 'Panthederm moisturizing cream for dry skin and Eczema (50 ml) Moisturizing cream for dry skin and very dry skin that may be prone to eczema.…', 3.4, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z700834307B8545F40052Z/45/_/1774238213/fd5c590e-cf66-4a32-ada6-94694f33aa18.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z700834307B8545F40052Z/45/_/1774238215/0109f34f-d414-498c-8b1c-aec314efe7dd.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z700834307B8545F40052Z/45/_/1774238439/df17e6a4-fcf9-497c-a7d8-4bce85368234.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z700834307B8545F40052Z/45/_/1774238216/fee55978-1360-42bb-8a15-b9366755b664.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'creams-moisturizers'), (select id from public.brands where slug = 'remedix'), 4.7, 43, 0, true, false, true, ARRAY['skin', 'care', 'creams', 'moisturizers', 'face']::text[]),
  ('Revitalizing Shampoo and Conditioner With Argan Oil Sulfate Free Silicon Free and Paraben Free 800ml*2', 'revitalizing-shampoo-and-conditioner-with-argan-oil-sulfate-free-silic', 'Online shopping for maxCare natural.wonder. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for maxCare natural.wonder.', 8.7, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZA56ADC4F1E655D7B8515Z/45/1760425013/0164e9b3-adfa-43d6-b4e1-f986dd4a2990.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZA56ADC4F1E655D7B8515Z/45/1760254834/d00a324a-ed58-4db0-9c9e-991cf05ec6aa.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZA56ADC4F1E655D7B8515Z/45/1760254833/9222ec5b-01e3-46a6-94d7-e9918c38eeff.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZA56ADC4F1E655D7B8515Z/45/1760254833/6224774f-d90b-4c2e-990a-27e09a1a4582.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'shampoos-conditioners'), (select id from public.brands where slug = 'maxcare-natural-wonder'), 5, 1, 0, true, false, true, ARRAY['hair', 'care', 'shampoos', 'conditioners']::text[]),
  ('skala Expert Pota Desmaiado Cream 1000g', 'skala-expert-pota-desmaiado-cream-1000g', 'Online shopping for SKALA. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for SKALA. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Re…', 7.7, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z9233C2C0ECC7CD3F4254Z/45/1745243479/9e35ca28-9e92-4b2d-8d26-699bc49c8d7d.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'hair-scalp-treatments'), (select id from public.brands where slug = 'skala'), 5, 1, 0, true, false, true, ARRAY['hair', 'care', 'scalp', 'treatments', 'oil', 'serums']::text[]),
  ('Elixir Ultime Original Refillable Hair Oil 75ml', 'elixir-ultime-original-refillable-hair-oil-75ml', 'The bestselling, iconic Kérastase Elixir Ultime hair oil is now refillable. This leave-in hair oil, with its unforgettable shine and addictive fragrance delivers softness and nourishment to all types of hair, making it the best hair oil for dull hair. Deeply luxurious, this shiny hair oil is formulated with a combination of wild camellia and French camellia, delicately harvested by hand in Brittany, France. Lightweight, and gently scented with the iconic Kérastase perfume, this hair oil is a multi-sensorial and highly versatile hair treatment. It can be used as a pre-cleanse, or a pre-blow dry oil, and for finishing and touch-ups during the day to leave the hair smoother and more manageable. After 2 drops: +100% more shine* +70% instant softness** -76% less frizz during 96H** *instrumental test after 48H **instrumental test The golden bottle of this iconic shiny hair oil is now refillable and comes in two-pieces: an outer bottle made of 30% recycled glass and a refill made with 95% recycled plastic***. Design to last, this bottle can be continuously refilled.**** ***Except the pump, the label and colorants/additives ****Only on the 75ml refillable format and 75ml refill format.', 'The bestselling, iconic Kérastase Elixir Ultime hair oil is now refillable.', 30.914, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZE87C84ECF60137D04692Z/45/1743952233/390a9628-a7ca-46bf-aafd-c917bb2dd366.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE87C84ECF60137D04692Z/45/_/1722935919/09abda8f-dd0c-4895-a679-a44bf6b47a26.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE87C84ECF60137D04692Z/45/_/1722935920/c38a84c0-c39a-4ec0-a94c-5264f6510ec5.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE87C84ECF60137D04692Z/45/_/1722935945/8f41764d-224d-429e-8abf-8e3c4e25f323.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'hair-scalp-treatments'), (select id from public.brands where slug = 'kerastase'), 3.6, 33, 0, true, false, true, ARRAY['hair', 'care', 'scalp', 'treatments', 'leave', 'treatment']::text[]),
  ('Avogain 5% Minoxidil Solution 50 ml 3 Month Supply 3 pack (50)ml', 'avogain-5-minoxidil-solution-50-ml-3-month-supply-3-pack-50-ml', 'Avogain 5% spray contains Minoxidil as an active ingredient, and it is used for men and women to treat baldness and hair loss. Effective in cases of genetic baldness Avogain 5% spray is specially designed for men because of its 5% concentration, it helps to treat male baldness Avogain 5% spray , effective in treating beard hair loss and increasing its growth', 'Avogain 5% spray contains Minoxidil as an active ingredient, and it is used for men and women to treat baldness and hair loss.', 8.2, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z04D4161DC2B2111C67BCZ/45/_/1777376106/97d284ac-4087-4a12-a7e3-40b644c178a3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z04D4161DC2B2111C67BCZ/45/_/1777376106/cc1c36ae-ad39-4f22-8c86-693397e76865.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z04D4161DC2B2111C67BCZ/45/_/1777376106/0b89a913-d37c-472e-80d1-ea62cd01ea57.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z04D4161DC2B2111C67BCZ/45/_/1777376106/5c827170-a920-425c-962f-14016e61f18a.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'hair-scalp-treatments'), (select id from public.brands where slug = 'avalon-pharma'), 4.3, 8294, 0, true, false, true, ARRAY['hair', 'care', 'scalp', 'treatments', 'loss', 'products']::text[]),
  ('1200 Watt Hair Dryer Brush Ceramic Dryer And Styler 2 In 1 Professional Black/Beige', '1200-watt-hair-dryer-brush-ceramic-dryer-and-styler-2-in-1-professiona', 'Want a hairstyle that will make you stand out, but had no time to visit the salon? With this hair dryer, you can create stylish hairstyles quickly and conveniently. It is a handy tool with high output and is sleek enough to be carried anywhere. Hairdryers usually make your hair charged with ions after straightening it down, which makes it look messy and uneven and may be attracted to anything charged near it, but the 2-in-1 Hair Dryer works differently, as it has side combs that get rid of negative ions and remove excess moisture and frizz. It detangles, smoothly directs the hair in the direction you are styling, and gives you the desired result you want. It is easy to use quickly to tidy up hair and bangs before heading to a party or work. Hair Styling Brush 2x1 : A unique hairdryer and styler that makes your hair perfect. Features Ionic tech that leaves your hair smooth and beautiful. It has three different tool settings Heat, High and Low For daily use, fine to medium hair smooth, blow-dry, straighten, shape and polish-all with one easy tool In one step you can create the perfect hair look. Three different tool settings: Heat: Heated brush, no airflow High: Heated brush and high-speed dryer Low: Low-speed dryer', 'Want a hairstyle that will make you stand out, but had no time to visit the salon? With this hair dryer, you can create stylish hairstyles q…', 8.5, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z0AAE36B2D309172A2511Z/45/1755501765/8760a4ae-82b8-4d25-86da-16489d08aa4a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0AAE36B2D309172A2511Z/45/_/1720417858/999b62d3-744d-4546-b522-2920e9c4e11e.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0AAE36B2D309172A2511Z/45/_/1720417867/c70ad199-66c3-4e8d-bbff-8e8fab5dc2f6.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0AAE36B2D309172A2511Z/45/_/17204178