  ('NIVEA MEN Cool Kick Deodorant Spray, 72h Protection, Quick Dry, Pack of 3 (150ml each)', 'nivea-men-cool-kick-deodorant-spray-72h-protection-quick-dry-pack-of-3', 'NIVEA MEN Cool Kick Deodorant Spray offers a refreshing burst of invigorating freshness while providing reliable protection for up to 72 hours. This quick-dry anti-perspirant features a mild Cool-Care formula that effectively regulates perspiration and revitalizes the body. With its stimulating scent, it ensures a long-lasting fresh feeling throughout the day. Dermatologically proven for skin tolerance, this deodorant is alcohol-free, making it suitable for daily use.', 'NIVEA MEN Cool Kick Deodorant Spray offers a refreshing burst of invigorating freshness while providing reliable protection for up to 72 hou…', 3.751, NULL, 'BHD', '["https://f.nooncdn.com/p/98567ec96a7e5983929c1059bcae59d7|pzsku/Z2DFDB14054BC1FBEEB90Z/45/1770627130/0bd40438-88ea-4b86-bc8a-50546404b89d.jpg?width=1200","https://f.nooncdn.com/p/98567ec96a7e5983929c1059bcae59d7|pzsku/Z2DFDB14054BC1FBEEB90Z/45/1770627130/98c0f9c5-01cc-483c-aea7-7181888b8e92.jpg?width=1200","https://f.nooncdn.com/p/98567ec96a7e5983929c1059bcae59d7|pzsku/Z2DFDB14054BC1FBEEB90Z/45/1770627130/8ce773fe-b38d-46aa-a89d-85c1a33c0505.jpg?width=1200","https://f.nooncdn.com/p/98567ec96a7e5983929c1059bcae59d7|pzsku/Z2DFDB14054BC1FBEEB90Z/45/1770627130/b3c302a5-51a1-4e4e-8628-dc2615b9546d.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'deodorants-antiperspirants'), (select id from public.brands where slug = 'nivea'), 4.4, 48, 0, true, false, true, ARRAY['personal', 'care', 'deodorants', 'antiperspirants']::text[]),
  ('Ayurvedic Soap - Turmeric Packaging may vary', 'ayurvedic-soap-turmeric-packaging-may-vary', 'Proficiently anchored to offer a higher level of functionality and efficiency. Premium material construction exhibits abrasion resistant durability. Multi-purpose design allows you to use it for various personal grooming', 'Proficiently anchored to offer a higher level of functionality and efficiency.', 0.315, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N29708571A/45/_/1764242460/877067b4-dfe7-4c6b-b077-b0f4f6814d86.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N29708571A/45/_/1764242460/e43b2f14-0e3f-4061-a812-c9c6d9562c82.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N29708571A/45/_/1764242462/626e69aa-a554-4b10-a0ba-a72da1387a34.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N29708571A/45/_/1764242461/b49f6fb1-3a6a-4c51-ac88-7c933e0b0341.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'bath-body'), (select id from public.brands where slug = 'pyary'), 4.4, 3564, 0, true, false, true, ARRAY['personal', 'care', 'bath', 'body', 'soaps']::text[]),
