  ('SaDM Shiny Kabuki Foundation Brush – Vegan, Cruelty-Free Buffer Brush for Flawless Foundation Application', 'sadm-shiny-kabuki-foundation-brush-vegan-cruelty-free-buffer-brush-for', 'Achieve a perfect, airbrushed base with our expertly designed kabuki foundation brush! This versatile brush effortlessly blends liquid or cream foundation for a seamless, streak-free finish. The densely packed, soft synthetic bristles buff makeup into the skin, creating a smooth, even complexion. Its lightweight aluminum handle provides comfortable control and precise application. Perfect for all skin types, especially sensitive skin.', 'Achieve a perfect, airbrushed base with our expertly designed kabuki foundation brush! This versatile brush effortlessly blends liquid or cr…', 2.64, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z7019397007B4C08D85AFZ/45/_/1740264296/7f6763f0-3636-4957-868a-9a60ca2ae0d4.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z7019397007B4C08D85AFZ/45/_/1740264306/a7a6168d-4aa9-45f6-9106-0652409cf650.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z7019397007B4C08D85AFZ/45/_/1740264317/b1b48082-006b-4d5a-b0f6-a835a4eb765d.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z7019397007B4C08D85AFZ/45/_/1740264327/69b95ef4-0a90-4c9b-a42d-e704a7d3f81d.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'sadm-shiny'), 5, 5, 0, true, true, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('Dual-Ended Foundation Brush', 'dual-ended-foundation-brush', 'Revolutionize your foundation routine with the Build & Blend Brush. This innovative, dual-ended tool is your secret to a flawless, airbrushed finish, designed to eliminate streaks and patches. It''s the only brush you''ll need for a smooth, natural-looking complexion every time.', 'Revolutionize your foundation routine with the Build & Blend Brush.', 6.7, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z62BAA35C081C069AA76DZ/45/1758481095/667ec5da-4c28-4b87-beba-9049aeec2210.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z62BAA35C081C069AA76DZ/45/1758481096/6feee5e0-cd3e-42d8-af2f-77584f206431.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z62BAA35C081C069AA76DZ/45/1758481096/977ea0b5-6097-45c0-8942-0fd77b0034d6.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z62BAA35C081C069AA76DZ/45/1758481096/184b9ce9-a50f-491f-8bfd-4c7bdf8d83b6.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'sadm-shiny'), 5, 5, 0, true, true, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('Kabuki Foundation Makeup Brush, White, Synthetic Hair, Professional Face Brush with Retractable Handle, Portable Wand Design', 'kabuki-foundation-makeup-brush-white-synthetic-hair-professional-face', 'PREMIUM DESIGN: Professional-grade kabuki foundation brush with soft synthetic bristles and elegant champagne gold metallic handle for flawless makeup application. VERSATILE APPLICATION: Perfect for applying liquid foundation, powder, cream products, and mineral makeup with smooth, streak-free results. ERGONOMIC HANDLE: Lightweight metal handle provides comfortable grip and precise control for professional-level makeup application. DENSE BRISTLES: High-quality synthetic hair bristles are densely packed for optimal product pickup and seamless blending. TRAVEL-FRIENDLY: Compact size with protective cap makes it ideal for on-the-go touch-ups while maintaining professional quality', 'PREMIUM DESIGN: Professional-grade kabuki foundation brush with soft synthetic bristles and elegant champagne gold metallic handle for flawl…', 3.54, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z8944B587E6CB7D5651B4Z/45/1758478009/b9fbbc4b-7481-4a47-a098-3e7d7eb2f3f6.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8944B587E6CB7D5651B4Z/45/1758478008/026c3b08-b419-4556-aefa-9cb8735d7846.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8944B587E6CB7D5651B4Z/45/1758478009/d8702cda-a191-4e3f-9e67-2f603730e31c.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8944B587E6CB7D5651B4Z/45/1758478009/1e43c962-7383-4b5e-bf86-2e1934f9c92a.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'sadm-shiny'), 5, 3, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('Makeup Brush Set', 'makeup-brush-set', 'Online shopping for Generic. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for Generic. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free…', 2.9, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z31B2A484019DF290252AZ/45/_/1730455888/a7d3d0c4-ac12-4248-ba72-353a9f32f55c.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'generic'), 4.5, 10, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('Large foundation brush for instant blending and a velvety finish - T04', 'large-foundation-brush-for-instant-blending-and-a-velvety-finish-t04', 'Flat Foundation Brush from Trenz - For Flawless Makeup Application Enjoy a professional makeup look with the flat foundation brush from Trenz, specially designed for perfect application of liquid or powder foundation. The dense, soft bristles ensure even coverage and seamless blending, making your skin look radiant and flawless. It can also be used for distributing concealer and polishing makeup easily, giving you a natural finish and a long-lasting perfect look. How to Use the Foundation Brush: Apply a small amount of foundation or concealer to the back of your hand or directly on your face. Using the brush, start distributing the product with stippling or buffing motions on the skin. Make sure to blend well for even coverage, focusing on areas that need extra coverage. Enjoy a streak-free finish and a balanced appearance. Tips for Caring for Makeup Brushes: Wash the brush regularly with warm water and gentle soap to maintain the cleanliness of the bristles. Allow the brush to dry completely after cleaning by placing it on a dry towel, away from direct sunlight. Avoid using the brush on irritated or allergic skin. Frequently Asked Questions: Is this brush suitable for all skin types? Yes, it is designed to suit all skin types and ensures even distribution of foundation without causing irritation. What is the best way to clean the brush? It is best to wash it with warm water and a makeup brush soap, drying it horizontally to avoid distorting the bristles. How often should the brush be washed? To maintain skin cleanliness and coverage quality, it is advisable to wash the brush at least once a week. Product Story: The foundation brush from Trenz embodies beauty and simplicity in application. Specifically designed to deliver flawless makeup, its dense and soft bristles provide precise distribution and perfect coverage for foundation. This brush gives you professional results, making makeup application a comfortable and easy experience, helping you highlight your natural beauty and radiant look. About Trenz: In a world filled with choices, "Trenz" stands out as a distinguished Saudi brand, dedicated to providing products focused on beauty and health to meet the needs of the modern woman. Founded with a clear vision and noble goal: to empower women to feel confident and beautiful every day through innovative, high-quality products. We have curated a diverse range of products that includes makeup brushes, makeup sponges, mirrors, nail files, and more. Each product is the result of thorough research and attention to detail, ensuring we provide the best for you. "Trenz" is not just a brand; it is your companion in beauty and health. We are here to be part of your daily journey towards beauty and self-care. Join us and discover how our products can add a touch&nbs', 'Flat Foundation Brush from Trenz - For Flawless Makeup Application Enjoy a professional makeup look with the flat foundation brush from Tren…', 2.49, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZBF03540F1B12FF3455CCZ/45/_/1781816154/03bfe55a-91f8-4dcc-908b-5bc2ef351c4d.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZBF03540F1B12FF3455CCZ/45/_/1728425953/3c851890-eb9d-4f81-abd6-e2a69ded1672.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZBF03540F1B12FF3455CCZ/45/_/1728517395/52e475b8-0a1d-4a9b-9056-9b08d35d5090.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZBF03540F1B12FF3455CCZ/45/_/1728517405/888a6924-ae97-40a3-baf8-32d3505329f9.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'trenz'), 4.7, 56, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('Double-ended makeup brush for applying foundation on one side and contouring on the other - T09 and face makeup', 'double-ended-makeup-brush-for-applying-foundation-on-one-side-and-cont', 'Dual-Ended Makeup Brush – The Perfect Tool for Professional Makeup Application and Blending! This dual-ended makeup brush is the perfect addition to your makeup collection! With its practical design that combines two different functions, you can apply makeup effortlessly and professionally. The soft, dense bristles ensure smooth application without clumping, giving you a natural and even finish. It is suitable for all types of makeup, whether you are using creams, powders, or a combination of both. How to Use: Use the first side to apply and evenly distribute foundation or powder with a foundation brush. Use the second side for contouring or blending colors seamlessly with a contour brush or a blending brush for a flawless look. Clean your makeup brush regularly to maintain its quality and performance. Pre-Use Tips: Lightly mist your foundation brush with water when using cream products for a smoother application. Use a blush brush for a natural-looking blush application. Clean the brush regularly with mild soap or a makeup brush cleanser. Store it in a dry place away from moisture to maintain the bristles. Frequently Asked Questions: Is it suitable for all types of makeup? Yes, the concealer brush and blush brush are versatile and work well with both cream and powder products. Are the bristles harsh on the skin? No, the bristles are soft and gentle on the skin, ensuring a comfortable and safe experience. Product Story: This dual-ended brush is designed for makeup lovers who want an all-in-one tool instead of multiple brushes. With its practical design and multiple functions, it guarantees a perfectly blended makeup look with ease. Whether you need a blending brush or a blush brush , this brush is the perfect choice for you. Trenz Brand Story: In a world full of choices , Trenz stands out as a distinguished Saudi brand that focuses on beauty and health, catering to the modern woman’s needs. Founded with a clear vision and a noble goal, Trenz empowers women to feel confident and beautiful every day through innovative and high-quality products. We offer a wide range of beauty tools, including makeup brushes , beauty blenders, mirrors, nail files, and more. Each of our products is the result of meticulous research and attention to detail, ensuring we bring you only the best. Trenz is not just a brand; it is your beauty and wellness companion. We are here to be part of your daily beauty routine. Join us and discover how our products can add a touch of elegance and comfort to your life. Keywords: makeup brush, contour brush, concealer brush, foundation brush, blush brush, blending brush, highlight brush, large makeup brushes, face brushes, makeup tools, makeup brush set Additional Keywords: brush, brush makeup, foundation brush, makeup brush, makeup brushes', 'Dual-Ended Makeup Brush – The Perfect Tool for Professional Makeup Application and Blending! This dual-ended makeup brush is the perfect add…', 2.113, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z7CE7616FE75F9EEBD233Z/45/1761752158/15483550-36be-4d53-9465-07a13ddf61fd.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z7CE7616FE75F9EEBD233Z/45/1744752933/428f12eb-f14e-4f95-8f75-fcdccddcd353.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z7CE7616FE75F9EEBD233Z/45/1744752940/7521faff-8463-424c-9592-e9775aeba502.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z7CE7616FE75F9EEBD233Z/45/1744753171/22ba09a9-3483-4a8a-9507-df3883128107.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'trenz'), 4.6, 31, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('The On The Go makeup brush set contains ten makeup brushes plus a case - S07', 'the-on-the-go-makeup-brush-set-contains-ten-makeup-brushes-plus-a-case', 'Product Name: On-the-Go Portable Makeup Brush Set, Complete Function Small Beauty Brushes with Brush Case - 10 Brushes Usage Instructions: 1. Use the appropriate brush for each step of your makeup routine: the large brush for powder application, the smaller brushes for eyeshadow, the concealer brush for covering imperfections, etc. 2. Carry the included case with you when you''re out to be ready for makeup touch-ups anytime, anywhere. 3. After use, place the brushes back in the case to keep them clean and organized. 4. Regularly wash the brushes with a special brush cleaner to maintain their cleanliness and quality. Pre-Use Tips: - Use the brushes designated for each type of makeup to achieve professional results. - Clean the brushes regularly to prevent bacteria buildup and maintain healthy skin. - Use the included case to store and organize the brushes when not in use, and to easily carry them when traveling. Frequently Asked Questions: Q: Is this set suitable for travel? A: Yes, this set is designed with a compact, portable size, making it perfect for travel and daily use. Q: Are the brushes made of natural bristles? A: The brushes are made of high-quality bristles that ensure smooth and comfortable application, ideal for all types of makeup. Product Story: The "On-the-Go" makeup brush set by Trenz is the perfect solution for any woman looking for professional quality and convenience in her makeup application, whether at home or on the move. The set includes 10 different brushes to meet all your needs, from powder application to eye definition. The included case is stylish and modern, making it easy to carry your brushes wherever you go, making it the perfect choice for the modern woman who cares about her appearance at all times. Trenz Story: At Trenz, we are committed to offering beauty products that combine quality and practicality to meet the needs of the modern woman. The "On-the-Go" makeup brush set embodies our vision of providing products that simplify your daily routine and make caring for your beauty easier and faster, while ensuring the best results. Tagline: Trenz - Your Beauty Deserves the Best Product Keywords: Makeup brush set, portable beauty brushes, travel makeup brushes, Trenz products, small beauty brushes, brush case, beauty tools, 10-piece brush set', 'Product Name: On-the-Go Portable Makeup Brush Set, Complete Function Small Beauty Brushes with Brush Case - 10 Brushes Usage Instructions: 1…', 3.25, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZD92DDC1198B9AF82BBB8Z/45/_/1722173399/10723e58-c3e5-404f-a294-f1cfc8856fb3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD92DDC1198B9AF82BBB8Z/45/_/1724594828/51b73f5e-9d8e-420c-bb66-1f52db721caa.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD92DDC1198B9AF82BBB8Z/45/_/1724594818/a030ba8a-88bd-49ff-8a5a-bf3dbeddbf0b.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZD92DDC1198B9AF82BBB8Z/45/_/1724594839/b9616169-bef0-4eeb-9739-03c819935007.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'trenz'), 4.4, 190, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('TRENZ Professional Triangular Concealer Brush - T08', 'trenz-professional-triangular-concealer-brush-t08', 'Professional Triangle Concealer Brush by Trenz - Perfect Coverage for the Under-Eye Area Discover professional coverage for skin imperfections and dark circles with the triangle concealer brush from Trenz. This brush is specifically designed for precise application under the eyes and effective coverage of spots and blemishes, giving you a consistent and natural appearance. Product Details: Perfect Design for the Under-Eye Area: The concealer brush features a uniquely sculpted shape that comfortably fits into the under-eye area, focusing on precise coverage of imperfections and dark circles. Its triangular design and symmetrical bristles provide 360 degrees of coverage and even blending. Soft Synthetic Bristles that are Easy to Clean: The bristles are made from high-quality synthetic materials, making them easy to clean and ensuring their longevity without damage. Suitable for applying all types of liquid and powder makeup. Perfect Coverage for Blemishes and Imperfections: This brush is designed with the right density to accurately cover all skin flaws, ensuring a natural and refreshed look. Pre-Use Tips: Use the brush in gentle, circular motions to blend the concealer evenly. Wash the brush regularly to maintain its cleanliness and quality. When using powder, tap gently to remove excess before application for a natural appearance. Frequently Asked Questions: Can it be used with liquid and powder concealers? Yes, the brush is suitable for applying both liquid and powder concealers with equal efficiency. Are the bristles safe for sensitive skin? Yes, the synthetic bristles are soft and safe for use on all skin types, including sensitive skin. What is the best way to clean the brush? You can clean it using mild soap and water, then let it air dry to maintain the quality of the bristles. Product Story: The Trenz Concealer Brush is specifically designed to provide professional performance, making it easy to achieve consistent coverage and a natural look. With its perfect design and soft bristles, the brush offers even and comfortable application in the under-eye area and on all skin imperfections. It is the ideal companion for any woman seeking an elegant finish. Trenz Brand Story: In a world full of choices, "Trenz" stands out as a distinguished Saudi brand dedicated to offering products focused on beauty and health, catering to the needs of the modern woman. Established with a clear vision and noble purpose, Trenz empowers women to feel confident and beautiful every day through innovative, high-quality products. Our diverse collection includes makeup brushes, sponges, mirrors, nail files, and more. Each product is the result of thorough research and attention to detail, ensuring the best for you. "Trenz" is more than just a brand; it’s your companion in beauty and self-care. We are here to be part of your daily journey towards beauty and self-care. Join us and discover how our products can add a touch of elegance and comfort to your life. Trenz - Confidence in Every Touch Keywords: concealer brush, under-eye brush, makeup brush, blemish coverage brush, Trenz beauty brush.', 'Professional Triangle Concealer Brush by Trenz - Perfect Coverage for the Under-Eye Area Discover professional coverage for skin imperfectio…', 1.97, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZCCEDFD6D9CB29229AFF0Z/45/_/1728515270/2c85862e-e1f3-47b3-8375-95ff63b7369c.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZCCEDFD6D9CB29229AFF0Z/45/_/1728515281/6dc10337-22c9-4d5e-b4e0-8c00a897f9dc.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZCCEDFD6D9CB29229AFF0Z/45/_/1728515291/7cfd8d7c-0ac8-4b89-8f14-4e016aa570fb.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZCCEDFD6D9CB29229AFF0Z/45/_/1728515301/31d09ac7-4c56-42d7-a68a-ce8646a694df.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'trenz'), 4.4, 127, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('SaDM Shiny Mini Foundation Brush – Versatile Makeup Brush for Foundation, Powder, & Blush Application', 'sadm-shiny-mini-foundation-brush-versatile-makeup-brush-for-foundation', 'Achieve a flawless, professional-looking makeup application with our mini foundation brush! This versatile brush seamlessly blends liquid, cream, or powder foundation, blush, and loose powder for a smooth, airbrushed finish. Its compact size makes it perfect for travel and on-the-go touch-ups. The high-quality synthetic bristles are soft, durable, and easy to clean. A must-have addition to any makeup kit.', 'Achieve a flawless, professional-looking makeup application with our mini foundation brush! This versatile brush seamlessly blends liquid, c…', 2.22, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z64723B59566C8A1C10B2Z/45/_/1740262540/60cc0dbc-0c39-4533-8c97-a078deda77a3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z64723B59566C8A1C10B2Z/45/_/1740262550/ecfefb43-736d-4eca-8368-7851ebe2cfb4.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z64723B59566C8A1C10B2Z/45/_/1740262570/fec513f6-2a91-42e3-a779-b2853bd30fe0.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z64723B59566C8A1C10B2Z/45/_/1740262581/9ac50a37-c9c0-4967-ba75-f8a1df87480a.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'sadm-shiny'), 0, 0, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('DUcare 5-Piece Dual-Ended Eye Brush Set with Travel Pouch – Professional Eyeshadow, Blending, Eyeliner & Contouring Brushes (Vegan)', 'ducare-5-piece-dual-ended-eye-brush-set-with-travel-pouch-professional', 'DUcare Pro 5-Piece Eye Brush Set: Master Every Eye Look Craft runway-ready eyes with this versatile kit designed for precision and portability: 1-1 Blending Brush For smudging eyeshadow. Sweep back and forth on eyes with eyeshadow to achieve a satisfying look. 1-2 Blending Brush For smudging eyeshadow. Sweep back and forth on eyes with eyeshadow to achieve a satisfying look. 2-1 Concealer Brush With concealer, gently press on the parts of the face that need to cover blemishes, easily cover pores and acne marks. 2-2 Nose Contour Brush For reshaping nose. Use the brush to draw two contour lines down the sides of your nose, and highlight the bridge of your nose. 3-1 Eyeshadow Brush-L Apply eyeshadow, for a entire base of your eyelid. 3-2 Eye Shadow Brush-M Packs on eyeshadows & shades and works for any area of the eye. 4-1 Fan Brush-S Use to brush your powder highlight products, and to sweep shimmer onto the highest points, also can be used for sweeping off any excess product. 4-2 Detail Brush For eye detail processing, such as eye corners, eye tails and other detail parts. 5-1 Eye Shadow Brush-S Packs on eyeshadows & shades and works for any area of the eye. 5-2 Eyebrow Brush For drawing eyebrows. Outline the eyebrow first, then fill it with powder inward. Why Artists Recommend It: ✅ Pro Results, Zero Fuss: Synthetic fibers hold pigment without soaking excess product. ✅ Compact & Durable: Zippered pouch fits in clutch bags. Brushes resist bending or fraying. ✅ Ethical Glam: PETA-approved vegan materials + recyclable packaging. Perfect For: Bridal makeup requiring quick tool switches Minimalists who hate bulky kits Sustainable beauty shoppers', 'DUcare Pro 5-Piece Eye Brush Set: Master Every Eye Look Craft runway-ready eyes with this versatile kit designed for precision and portabili…', 3.507, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z72F6CC5F26B0799DEAB0Z/45/1743573213/109b82d7-0e23-44b8-9d06-831d05bf76e9.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z72F6CC5F26B0799DEAB0Z/45/1747645221/c0fe1906-277c-433c-8f02-bd7e189447a3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z72F6CC5F26B0799DEAB0Z/45/1747645226/db2e39a1-5fd1-4c47-9989-a6e3b944c24c.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z72F6CC5F26B0799DEAB0Z/45/1747645287/c1a88055-75e5-4469-99e1-3e8f5808308f.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'ducare'), 5, 2, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'brushes']::text[]),
  ('Bogenia Professional Concealer Brush BG200.020', 'bogenia-professional-concealer-brush-bg200-020', 'A brush designed to apply all types of concealers and correcting creams and enjoy a natural finish.', 'A brush designed to apply all types of concealers and correcting creams and enjoy a natural finish.', 3.3, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z521139C752A01E606DB2Z/45/_/1738480959/480041a0-a957-49c5-9fef-0e124595c87d.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z521139C752A01E606DB2Z/45/_/1738480969/17a630ec-d11a-4290-9c02-38230fe78426.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'bogenia'), 4.6, 117, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('Travel Fantasy Mini Brush Set Multicolour', 'travel-fantasy-mini-brush-set-multicolour', 'Latex-Free. Ideal for facial cleansing', 'Latex-Free. Ideal for facial cleansing', 5.5, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZA927B00565367FA89BC8Z/45/_/1778231340/715ea83c-e9b5-4eea-b3be-5f5bfa754d9a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZA927B00565367FA89BC8Z/45/_/1778231340/fe660730-db09-46e0-82c9-db24caf15a37.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZA927B00565367FA89BC8Z/45/_/1778231340/21d857d1-33f6-48c5-8fe5-6c4b737a1ec9.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZA927B00565367FA89BC8Z/45/_/1778231340/295122ec-2d5f-4972-acff-c812de90de74.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'real-techniques'), 4.5, 329, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('TRENZ Double-Ended Foundation Brush - T06', 'trenz-double-ended-foundation-brush-t06', 'Duo foundation & contour brush: Create professional contoured look with matte hand crafted handle and soft hair . Good flawless makeup foundation brush.only a small quantity of foundation on the brush is needed for the best results.. Multi-functional, double-ended face brush good flawless makeup for powder, liquid, concealer, cream, blush, concealer, foundation cosmetics.. Easy Controlled Handles - Our 100% handcrafted brushes, designed by experienced craftsmen, feature durable yet lightweight handles, perfected through multiple fixing processes for long-lasting usage.', 'Duo foundation & contour brush: Create professional contoured look with matte hand crafted handle and soft hair .', 2.249, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z5BBD445F74C71C77388AZ/45/1767808708/fa235851-a4c8-41dd-a60b-9f98fcaee8f9.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z5BBD445F74C71C77388AZ/45/1751572672/e62d329d-c36a-4195-ace5-aad1f075da19.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z5BBD445F74C71C77388AZ/45/1751572692/e1dc5ad9-bc16-42e5-aced-c1f33f09b6b5.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z5BBD445F74C71C77388AZ/45/1751572753/b4eb4a2f-e713-406a-9741-09aa7ba72498.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'trenz'), 4.5, 54, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('Contour brush with angled tip - T10', 'contour-brush-with-angled-tip-t10', 'Its clever design and ultra-soft bristles help you effortlessly contour your face and define your features, enhancing your beauty without any effort. It blends color quickly and gives a natural finish, whether you''re using powder or cream.', 'Its clever design and ultra-soft bristles help you effortlessly contour your face and define your features, enhancing your beauty without an…', 1.95, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z4D9536C7538C63B873ADZ/45/1746232927/ad1dadc4-08ed-4122-96f8-67ffe1c0dfa5.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4D9536C7538C63B873ADZ/45/1746232927/5f2c625f-7f46-4b6e-b772-18a179d584d2.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4D9536C7538C63B873ADZ/45/1746232926/531cf3be-7ec1-4754-a5a7-727c134f8f0a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4D9536C7538C63B873ADZ/45/1746232927/fa4fc92f-b6af-4ef5-add7-eb9ed07c3fbe.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'trenz'), 4.7, 31, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'brushes']::text[]),
  ('Rosy Glow 4.4 Gr Blusher Rosewood', 'rosy-glow-4-4-gr-blusher-rosewood', 'Thanks to the color restoration technology, this powder blush reacts to the skin''s pH and moisture level instantly to give your skin a long-lasting, “customized” color. The skin remains fresh and radiant throughout the day. The ultra-soft, lightweight formula glides on and blends seamlessly into the skin for natural results, and can be layered as desired, with a lightweight, second-skin feel.', 'Thanks to the color restoration technology, this powder blush reacts to the skin''s pH and moisture level instantly to give your skin a long-…', 3.499, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z6E200EB8325B73B466EDZ/45/_/1779704144/7ff99a8e-0e82-4d6e-a12f-b5954c415145.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6E200EB8325B73B466EDZ/45/_/1779704144/b198248c-4f51-494e-b084-70d33554c0f3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6E200EB8325B73B466EDZ/45/_/1779704144/2f013352-d50c-4651-988a-c5573a2e78b3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6E200EB8325B73B466EDZ/45/_/1779704144/9ae40311-4505-4e9f-b217-4f8f3cad657d.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'dior'), 4.3, 161, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('Fit Me Matte & Poreless Powder 230 Natural Buff', 'fit-me-matte-poreless-powder-230-natural-buff', 'All-day mattifying powder with SPF 28. Enriched with mattifying minerals that fight sweat. Does not clog pores. Non-comedogenic. For oily skin', 'All-day mattifying powder with SPF 28. Enriched with mattifying minerals that fight sweat. Does not clog pores. Non-comedogenic.', 3.83, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N48739745A/45/_/1766380406/bef362f2-4cdf-4dae-bf70-ffb589250f4d.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N48739745A/45/_/1764236062/fb5c4bfe-13f1-49b4-bb43-c45770b7d915.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N48739745A/45/_/1764236060/1b9004f8-ebb7-48ab-9569-3fa3d55a82c9.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N48739745A/45/_/1764236060/0ed193f5-d0e2-4e8b-842b-eb13adbc15e1.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'maybelline-new-york'), 4.2, 2808, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('BODY FOUNDATION SPRAY LONG LASTING', 'body-foundation-spray-long-lasting', 'Online shopping for ROSE BERRY. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for ROSE BERRY. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Fr…', 3.195, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z0989DD1881639EC15087Z/45/1748191752/089146c9-c03b-4300-945b-3ab93113c4ba.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'rose-berry'), 4.2, 36, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('Hd Liquid Coverage 010 Foundation 30 ml 010 Light Beige', 'hd-liquid-coverage-010-foundation-30-ml-010-light-beige', 'Ultra-lightweight,highcoveragefoundationforanaturallookingfinish. Coversimperfectionsandmattifiestheskincreatingasmoothandevencomplexionforupto24hours. Featuresanuniquedropperapplicator. Mattifying,providesasecondskineffect', 'Ultra-lightweight,highcoveragefoundationforanaturallookingfinish.', 3.435, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N11073247A/45/_/1767608013/6d186b3b-9ec9-4e5f-9634-a79a724d45b6.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11073247A/45/_/1764241805/18160508-eeac-4a30-a35f-d91875ab8825.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11073247A/45/_/1764241806/cb71b3c3-8d81-4dae-a153-f540e3cb2b6e.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11073247A/45/_/1764241807/17532aae-6e40-46e6-a532-553ec873d4f8.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'catrice'), 4.3, 725, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('Fit Me Matte + Poreless, Normal to Oily – 220 Natural Beige 220 Natural beige', 'fit-me-matte-poreless-normal-to-oily-220-natural-beige-220-natural-bei', 'Fit Me® Matte + Poreless Foundation face makeup. This lightweight foundation mattifies and refines pores and leaves a natural, seamless finish. Ideal for normal to oily skin, our exclusive matte foundation formula features micro-powders to control shine and blur pores. Pore minimizing foundation. Dermatologist tested. Allergy tested. Non-comedogenic. How to use: Apply foundation onto skin and blend with fingertips or an applicator.', 'Fit Me® Matte + Poreless Foundation face makeup.', 4.595, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N11073359A/45/_/1774602893/da94940f-aeb3-43c8-8b3d-ded991dce787.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11073359A/45/_/1764242281/3685fdd7-04c8-40ec-939d-29570501dfe4.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11073359A/45/_/1764242282/e683492f-03cc-4f9d-b54c-d6959570711d.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11073359A/45/_/1764242281/1c7b8dfe-8305-4c1a-8fbf-ced9d5842b79.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'maybelline-new-york'), 4.2, 638, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('Leg Makeup Waterproof No Transfer, Leg Cover up Makeup Long Lasting Body Foundation', 'leg-makeup-waterproof-no-transfer-leg-cover-up-makeup-long-lasting-bod', '【Multiple Uses】Our waterproof body makeup it not only for leg makeup but also to cover tattoos and varicose veins, ensuring you look flawless for any occasion.. 【Mild Formula】Formulated with ingredients suitable for sensitive skin types, our body foundation provides a comfortable feel on your skin and can be used by individuals of all ages, allowing you to confidently show off your skin.. 【Long Lasting & Waterproof】Our waterproof leg makeup delivers a no-transfer, waterproof, and sweatproof finish on your face and body, ensuring lasting coverage even in challenging conditions such as rain or during face and body washing.. 【Easy to Use】Perfect for those who prefer a hassle-free application, our body foundation is easy to use. Simply choose the suitable color for your skin tone and enjoy perfect skin coverage. It''s also great for color correction.. 【How to Use】Start by squeezing out the lotion and applying it evenly on the skin of your legs. Wait for 5-10 minutes, then gently pat to allow the emulsion to blend seamlessly into your skin, creating a beautiful skin condition.', '【Multiple Uses】Our waterproof body makeup it not only for leg makeup but also to cover tattoos and varicose veins, ensuring you look flawles…', 4.4, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z0E1E5972DED493013BCCZ/45/1747025554/3188b1ae-a56c-44be-9518-2330fad70ea1.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0E1E5972DED493013BCCZ/45/1747025534/34b59f69-4e23-4c5b-b63c-279d9ed1de82.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0E1E5972DED493013BCCZ/45/1747025555/e5899e8d-2179-4521-892f-f84e8e6610db.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0E1E5972DED493013BCCZ/45/1747025554/11774ec2-7380-4329-bc0d-4af391c2023f.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from publi