  ('Fit Me Matte & Poreless Powder 330 Toffee', 'fit-me-matte-poreless-powder-330-toffee', 'Online shopping for MAYBELLINE NEW YORK. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for MAYBELLINE NEW YORK. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless…', 3.805, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N48739746A/45/_/1764242518/61a0817b-44e3-4cd2-bcfd-9496291a6ddd.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N48739746A/45/_/1764242519/ee231838-2d41-445a-881c-6b748daa5904.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N48739746A/45/_/1764242516/012e80a1-82e1-4ad2-aaba-e46d6f946fcc.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N48739746A/45/_/1764242520/0459befe-5d37-413f-bc6a-21b44cdfb34e.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'maybelline-new-york'), 4.2, 2808, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('TLM Colour Changing Foundation for Different Skin Tone, Foundation Makeup Base Nude Face Liquid Full Coverage Concealer, TLM Concealer Cover Cream', 'tlm-colour-changing-foundation-for-different-skin-tone-foundation-make', 'Colour Changing Foundation is a revolutionary new liquid foundation that goes on white and instantly self-adjusts to match your EXACT skin tone.. It is designed for daily use and will give your skin that illuminating silky finish other foundations just don’t provide. it lightweight and quickly absorbs onto the skin without any dryness or caking.. Our unique color-matching formula protects and moisturises the skin as it works to even out your complexion.. This color match foundation contains sun protection to shield your skin.. It''s very lightweight,portable to carry and easy to apply. A great gift for your girlfriend, wife and families. A great gift for women,girls.', 'Colour Changing Foundation is a revolutionary new liquid foundation that goes on white and instantly self-adjusts to match your EXACT skin t…', 2.098, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZE6DF9890092210EA1A11Z/45/1747209037/96fac5df-3eda-43a1-87a5-af9852f19115.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE6DF9890092210EA1A11Z/45/1747209037/cd5c0d17-03f4-428b-b247-1f5b92e8a011.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE6DF9890092210EA1A11Z/45/1747209036/296e52a4-cac1-4ac5-a3d6-694b1694910a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE6DF9890092210EA1A11Z/45/1747209037/f41fb0c4-096a-487d-a459-9b80615368e5.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'tlm'), 4, 188, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('Makeup Cover 211', 'makeup-cover-211', 'The clinically tested, extreme covering Make-up Cover was created as the first of its kind in Europe and one of the first in the world. The license for this foundation was eventually sold to Hollywood. It contains 50% pigments, which makes it a target against skin imperfections. DERMACOL MAKE-UP COVER provides PERFECT COVERAGE even in thin layers and is the perfect corrector for dark under-eye, unpleasant spots and skin blemishes. It completely covers acne, loss of pigmentation, post surgical bruising, tattoos etc. It may be used on the entire face or body for color correction, darkening or lightening the skin tones, and ensuring ideal balance. It is widely used as a professional make-up for photo or film shoots, modeling and for festive occasions.', 'The clinically tested, extreme covering Make-up Cover was created as the first of its kind in Europe and one of the first in the world.', 3.305, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZB496790319BA2B75A18FZ/45/_/1680918151/bbae86c0-a40d-4eff-8624-9545724e60eb.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZB496790319BA2B75A18FZ/45/_/1680918152/4ac8f776-6237-472f-8ee4-b13b9daaa0af.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZB496790319BA2B75A18FZ/45/_/1680918153/c4227e44-0e0a-4ebf-834d-8cf8f12a0479.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZB496790319BA2B75A18FZ/45/_/1680918154/ea2e4569-7200-4b8b-b9f3-e6758e0208cc.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'dermacol'), 4.3, 263, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('Natural Radiant Longwear Liquid Foundation Mont Blanc Mont Blanc', 'natural-radiant-longwear-liquid-foundation-mont-blanc-mont-blanc', 'Ingredients- Dimethicone, Water/aqua/eau, Phenyl Trimethicone, Glycerin. How to use- Dispense one pump or a pearl sized amount of natural radiant longwear foundation and warm with fingertips', 'Ingredients- Dimethicone, Water/aqua/eau, Phenyl Trimethicone, Glycerin.', 14.85, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZBE85F45283B4C98C4FF0Z/45/_/1779179245/d39451eb-0ca2-42e8-a845-90e7fca2c5c1.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZBE85F45283B4C98C4FF0Z/45/_/1779179245/2e054152-8bd4-43e7-a8ce-d888ce75d475.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZBE85F45283B4C98C4FF0Z/45/_/1779179245/59461b3e-8672-4a2a-9f6f-3665a579ca48.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'nars'), 4.3, 945, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('Lasting Performance, Liquid Foundation 35 ml 100 Fair', 'lasting-performance-liquid-foundation-35-ml-100-fair', 'Max Factor Lasting Performance Liquid Foundation guarantees 8 hours of stay put perfection. With a film-forming technology, it covers perfectly giving the appearance of firmer skin. Formula Specially designed lightweight silicones and a hard-wearing, touch proof system stand up to any amount of rubbing or touching - the foundation won''t even rub off on your clothes. The effective water-in-silicone emulsion guarantees high coverage, which lasts up to 8 hours, and provides the natural look without fading or streaking. Your natural look will stay in place from morning to evening. This Foundation is fragrance and oil free and is non-comedogenic, which means it won''t clog the pores. Make-up Tips To choose your perfect shade, match the foundation with the skin tone of your jawline. To ensure even coverage and deliver a perfect flawless base to your skin, apply a small amount of the foundation in the centre of your face and blend outwards with a foundation brush or your fingertips. Always apply the foundation in good natural light.', 'Max Factor Lasting Performance Liquid Foundation guarantees 8 hours of stay put perfection.', 6.5, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N11034110A/45/_/1767607653/ae4933e0-e245-4799-b37c-7f6628c5c456.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11034110A/45/_/1764235915/da8b3f98-4555-4359-85e7-c57f589f3acb.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11034110A/45/_/1764236061/f7228d98-5db4-4426-9878-addcd5ebfd29.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11034110A/45/_/1764236063/fb592e4b-d6ba-4b6d-a22f-148b7be00bdd.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'max-factor'), 4.4, 161, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'foundation']::text[]),
  ('Maxi Powder Blush 03 Wild Card', 'maxi-powder-blush-03-wild-card', 'Want the London look? Maxi Blush''s lightweight, powder formula gives cheeks a burst of colour and healthy looking glow. Whether you''re at the office, out shopping, or partying until the early hours, Maxi Blush''s pigmented formula delivers colour that lasts. Apply with powder brush over foundation or on bare skin. The micro-fine powders blend easily and provide buildable results. Available in 5 shades to compliment multiple skin tones. Rimmel London is an inner confidence that how we look is always cool, irreverent, never predictable and always evolving. Rimmel is not perfection or intimidating, it is like London: young, urban, eclectic, edgy. It is expression with no rules, it is real, it is accessible. Live the London Look.', 'Want the London look? Maxi Blush''s lightweight, powder formula gives cheeks a burst of colour and healthy looking glow.', 2.9, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N44981524A/45/_/1764241890/ae0802fe-c1b2-4ab8-9da5-75a7052e4529.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N44981524A/45/_/1764241891/ff0a54b2-15f9-4a32-902d-e44b561bf429.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N44981524A/45/_/1764241803/8024d5f4-d6d6-41c2-b29b-46101afe8466.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N44981524A/45/_/1764241890/4179534e-fc79-4460-9581-9275206e8165.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'rimmel-london'), 4.1, 1298, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Chic In Geek Soft Blush PF-F01', 'chic-in-geek-soft-blush-pf-f01', 'Enjoy a natural, fresh flush of color with Pink Flash''s Cheek ''n Geek Blush, which gives you a charming, natural look. Features: Richly pigmented formula: Provides intense, long-lasting color. Buildable: Adjust the intensity to achieve your desired look. Variety of shades: Matte and shimmery shades for all-day wear. Easy application: Soft, blendable powder provides even coverage without caking.', 'Enjoy a natural, fresh flush of color with Pink Flash''s Cheek ''n Geek Blush, which gives you a charming, natural look.', 1.157, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z33AD1A5AFFB96EBEC931Z/45/1751551611/405b5ad4-b013-485f-9ccf-b709928a3d4d.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z33AD1A5AFFB96EBEC931Z/45/1751551796/5618fa52-fbd8-481b-a0cd-e6f41b0e93c6.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'pink-flash'), 4.2, 27, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Matte Blush, God Mama #12, 3.2g', 'matte-blush-god-mama-12-3-2g', 'This matte blush by For You Too offers a refined finish for your makeup routine. Presented in a compact design, the product is identified as shade God Mama #12. It contains 3.2 grams of blush, suitable for daily application. The circular case features a smooth, uniform color with an embossed ''4U'' logo on the product pan, indicating the brand''s signature. The lid securely closes, making it convenient for portability. This blush is formulated to provide a matte effect, enhancing facial contours with its specific shade.', 'This matte blush by For You Too offers a refined finish for your makeup routine.', 2.967, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z996AB81270C1AAB908D9Z/45/_/1775294582/f3190415-5de0-41f8-8c60-23cfbadf3b5d.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = '4u2'), 5, 2, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Rosy Glow Blush 001 pink', 'rosy-glow-blush-001-pink', 'Rosy Glow Blush comes with a new clean formula* that blends seamlessly into the skin to instantly give cheeks a healthy, glowing effect. Thanks to the color restoration technology, this powder blush reacts to the skin''s pH and moisture level instantly to give your skin a long-lasting, “customized” color. The skin remains fresh and radiant throughout the day. The ultra-soft, lightweight formula glides on and blends seamlessly into the skin for natural results, and can be layered as desired, with a lightweight, second-skin feel. Rosy Glow blush comes in four new shades, and its colors are designed to precisely match skin tone and give a healthy, glowing effect that suits all skin types.', 'Rosy Glow Blush comes with a new clean formula* that blends seamlessly into the skin to instantly give cheeks a healthy, glowing effect.', 3.599, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZBCC04D9FDC95E5B05F58Z/45/_/1779705126/411f46f5-43eb-4b14-abeb-1c8c180c7539.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZBCC04D9FDC95E5B05F58Z/45/_/1779705127/8c6717de-eed4-41f5-9080-e8ba5fed0f65.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZBCC04D9FDC95E5B05F58Z/45/_/1779705127/5b8bbddd-62a6-4ce3-969d-f704b69904a1.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZBCC04D9FDC95E5B05F58Z/45/_/1779705127/536564f0-b41e-47f6-8ded-b4dff74e1715.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'dior'), 0, 0, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Rosy Blush Glow-012 Rosewood', 'rosy-blush-glow-012-rosewood', 'Rosy Glow Blush comes with a new clean formula* that blends seamlessly into the skin to instantly give cheeks a healthy, glowing effect. Thanks to the color restoration technology, this powder blush reacts to the skin''s pH and moisture level instantly to give your skin a long-lasting, “customized” color. The skin remains fresh and radiant throughout the day. The ultra-soft, lightweight formula glides on and blends seamlessly into the skin for natural results, and can be layered as desired, with a lightweight, second-skin feel. Rosy Glow blush comes in four new shades, and its colors are designed to precisely match skin tone and give a healthy, glowing effect that suits all skin types.', 'Rosy Glow Blush comes with a new clean formula* that blends seamlessly into the skin to instantly give cheeks a healthy, glowing effect.', 5.4, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z8EB98DA0FAB2D1F37B99Z/45/_/1779704281/984e6c4f-26ec-40b5-8e3d-9fdf8c97032b.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8EB98DA0FAB2D1F37B99Z/45/_/1779704282/fab4d898-9a23-46b1-a5c9-18620182d566.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8EB98DA0FAB2D1F37B99Z/45/_/1779704281/3dc9764f-b715-4367-8e61-216bb21523a3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8EB98DA0FAB2D1F37B99Z/45/_/1779704281/2b359ca1-9d0b-4810-b8f8-b07f6f2ce2ef.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'dior'), 0, 0, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Facefinity Blush 15 Seductive Pink', 'facefinity-blush-15-seductive-pink', 'About the product: Sometimes, a subtle flush of colour is the look you&rsquo;re after. Other times, a more striking contoured finish is what you want. The stunning multi-tonal shades of Max Factor Creme Puff Blush are designed to blend and build effortlessly, so you can achieve the perfect sweep of colour. Max Factor Creme Puff Blush is perfect for creating a subtle finish, a striking contours, and everything in between thanks to its easy-to-build formula. About the brand: In Hollywood''s Golden Age, when it came to make-up, only one name was on the lips of the silver screen stars - Mr Max Factor A visionary make-up artist, wig maker and inventor, Max Factor was known for creating the signature looks of the era&rsquo;s most famous icons and believed that glamour should be within reach of all women. From mascara to foundation, eye shadow to lip gloss &ndash; Max Factor put the transformative tools for make-up artistry into the hands of every woman, enabling her to create her own personal glamour statement every day. Ingredients: Mica, Talc, Triisostearin, Octyldodecanol, Dimethicone, Zea Mays Starch, Magnesium Aluminum Silicate, Phenoxyethanol, Sodium Dehydroacetate, Aqua, Calcium Aluminum Borosilicate, Sorbic Acid, Methylparaben, Ethylparaben, Ethylhexyl Methoxycinnamate, BHT, Disodium EDTA, Tin Oxide, Tocopheryl Acetate, Calcium Sodium Borosilicate, Synthetic Fluorphlogopite, Palmitic Acid, Hydrogenated Polyisobutene, Silica, [+/- CI 77891, CI 77491, CI 77492, CI 77742, CI 15880, CI 77007, CI 15850, CI 77499, CI 75470]. How to use: 1. Swirl a soft, clean brush over the blush and tap off excess before applying. 2. Sweep over the apples of the cheeks and blend using small, circular movements. 3. Build your colour to the desired shade. If you apply too much, simply sweep some translucent powder over the top to tone down the intensity.', 'Sometimes, a subtle flush of colour is the look you&rsquo;re after. Other times, a more striking contoured finish is what you want.', 5.4, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N11034023A/45/_/1764173645/9bc74f91-8f74-43ff-bbd9-64207ced3155.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N11034023A/45/_/1764241687/d70578bd-16e1-4793-b856-1c10a991a56b.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'max-factor'), 0, 0, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Baby Got Blush Stick | Shade 30 Rosé All Day | Cream Blush for Cheeks & Lips | Easy to Apply & Blend | Long Lasting Natural Rosy Glow | Travel Friendly | Vegan & Cruelty Free rosé all day', 'baby-got-blush-stick-shade-30-rose-all-day-cream-blush-for-cheeks-lips', 'Discover the perfect way to add a natural rosy glow to your makeup routine with the essence Baby Got Blush Stick in Shade 30 Rosé All Day. Designed for effortless beauty, this creamy blush delivers a silky, lightweight texture that blends seamlessly onto the skin. Whether you are getting ready for a day at the office, a night out, or just want a quick refresh, this blush stick is your ideal companion. Its convenient stick format makes application quick and easy—simply swipe directly on your cheeks and blend with your fingers or a brush for a flawless finish. Perfectly compact, it’s a must-have for touch ups on the go, fitting easily into any makeup bag or purse. This versatile product goes beyond just cheeks. Use it on your lips for a soft tint or on your eyelids for a coordinated monochromatic look that’s modern and chic. The shade 30 Rosé All Day is universally flattering, offering a fresh pop of rosy color that complements light, medium, and deeper skin tones. Made with a vegan and cruelty-free formula, this blush is free from gluten, parabens, and microplastic particles, giving you a clean beauty option without compromising on performance. Gentle on the skin and designed to enhance your natural beauty, it’s a perfect choice for anyone who values quality and conscious makeup. Elevate your daily makeup with essence Baby Got Blush Stick—a simple, portable, and effective way to achieve a radiant, healthy glow anytime, anywhere.', 'Discover the perfect way to add a natural rosy glow to your makeup routine with the essence Baby Got Blush Stick in Shade 30 Rosé All Day.', 1.9, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZF5DD209AA8742FF0133DZ/45/_/1779344441/ac238a6d-75c0-4985-b5ae-3c8aaf9e9f96.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZF5DD209AA8742FF0133DZ/45/_/1779344440/3563a25b-48e6-4299-8d59-e9b3ab0475cf.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZF5DD209AA8742FF0133DZ/45/_/1779344440/b4eef5cd-f105-4c88-9e86-14f45ae40fdc.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZF5DD209AA8742FF0133DZ/45/_/1779344440/23f51f9f-84b7-4fac-9fc9-2b651d8ae98d.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'essence'), 4.3, 368, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Dewy Blush Stick 3.5g', 'dewy-blush-stick-3-5g', 'Benefits: Smooth, creamy formula: Easy to blend, giving skin a natural, radiant finish. Versatile: Can be used as blush, lipstick, or eyeshadow. Rich, buildable color: Control the intensity of the color to achieve the desired look. Long-lasting: Fade-resistant, ensuring the color stays fresh for hours. Easy to apply: The handy stick design allows you to apply it directly to the skin without any mess. To use: Swipe the blush stick directly onto your cheeks, lips, or eyelids. Use your fingers or a brush to gently blend the color until you achieve your desired look. You can add more layers for a more intense color.', 'Benefits: Smooth, creamy formula: Easy to blend, giving skin a natural, radiant finish.', 1.59, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z42BFF291F82ED55EC663Z/45/1745043071/7e05cc2c-1338-422a-9cbf-c8b75a568d2f.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z42BFF291F82ED55EC663Z/45/1745043133/a6a2f65f-c2ef-40cc-a91b-69673a8abb53.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'pink-flash'), 0, 0, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Backstage Contour & Highlight Palette 002 10g GLITZ', 'backstage-contour-highlight-palette-002-10g-glitz', 'How to use: - Apply with your fingers or a brush. -Use each shade alone or blended together. - Using an angled brush, apply highlighter to cheekbones, bridge of nose, cupid''s bow, and chin. - Using a blush brush, apply blush to the apples of your cheeks.', 'How to use: - Apply with your fingers or a brush. -Use each shade alone or blended together.', 3.6, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZABF655F383D6CDE707D7Z/45/_/1779706435/01259196-e898-4d28-b90c-12f24e4e48ec.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'dior'), 4.1, 197, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Dasant Play Lipstick From Christian Pink', 'dasant-play-lipstick-from-christian-pink', 'Universal blush that awakens color - a natural, healthy glow Rosy Glow Blush is the secret weapon of Dior makeup artists to naturally create the look of rosy cheeks for a fresh, glowing effect. benefits This healthy glow booster illuminates cheeks with natural-looking color, like a breath of fresh air. Enriched with Color Reviver technology, it reacts to the skin''s moisture level when used for a customized rosy effect.', 'Universal blush that awakens color - a natural, healthy glow Rosy Glow Blush is the secret weapon of Dior makeup artists to naturally create…', 5.422, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z542BED12E0A611E25498Z/45/_/1779707469/7f85964d-385f-4726-9d39-edd61b5ce638.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z542BED12E0A611E25498Z/45/_/1779707469/14d4af74-6eac-418b-81e6-31494ca8a589.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z542BED12E0A611E25498Z/45/_/1779707469/ad39a511-df18-45da-9016-1ed427e0bf58.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'dior'), 4.6, 692, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('12 shades-Concealer & Blusher Multicolour', '12-shades-concealer-blusher-multicolour', 'Online shopping for Red Apple. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for Red Apple. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Fre…', 1.945, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N48938247A/45/_/1766380438/b20389ee-f116-464e-9753-dcb577178e50.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N48938247A/45/_/1764242269/fe8b37e6-bdbd-4e3f-9344-fa25d6fa895e.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N48938247A/45/_/1764242270/eab069da-46d9-45a0-b07b-8fc5faf18bf6.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'red-apple'), 3.9, 2503, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('Powder Blush Oh Baby! Pink (001)', 'powder-blush-oh-baby-pink-001', 'Ingredients Talc, Mica, Synthetic Fluorphlogopite, Zinc Stearate, C12-15 Alkyl Benzoate, Silica, Zea Mays (Corn) Starch, Polyethylene, Phenyl Trimethicone, Nylon-12, Kaolin, Barium Sulfate, Colophony/Rosin/Colophane, Ethylhexylglycerin, Methicone, Tocopherol, Phenoxyethanol, May Contain [+/-: Carmine (CI 75470)/Cochineal, Iron Oxides (CI 77491, 77492, 77499), Red 40 Lake (CI 16035), Red 6 (CI 15850), Red 7 (CI 15850), Titanium Dioxide (CI 77891) (Bound), Yellow 5 (CI 19140)]', 'Ingredients Talc, Mica, Synthetic Fluorphlogopite, Zinc Stearate, C12-15 Alkyl Benzoate, Silica, Zea Mays (Corn) Starch, Polyethylene, Pheny…', 3.704, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZE4A80AD0C3CC7CC8BAEAZ/45/_/1779705132/815b0b25-654c-4384-86e0-042fc4b22e7a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE4A80AD0C3CC7CC8BAEAZ/45/_/1779705132/1f369c24-7a8b-43c1-860b-44617cdc361c.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE4A80AD0C3CC7CC8BAEAZ/45/_/1779705132/07c62c0d-3ad7-49af-8d2c-a9757326e23f.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZE4A80AD0C3CC7CC8BAEAZ/45/_/1779705133/c0e172e5-b6cb-4faf-87b9-61a803e8d40f.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'face-makeups'), (select id from public.brands where slug = 'revlon'), 3.8, 51, 0, true, false, true, ARRAY['makeup', 'face', 'makeups', 'blusher', 'bronzer']::text[]),
  ('L''Oreal Paris Extensionist Mascara, Lengthening, Volumizing, and Curling Formula For a Lash Extension Eye Makeup Look, Washable Black', 'l-oreal-paris-extensionist-mascara-lengthening-volumizing-and-curling', 'Use the sculpting comb brush to precisely and easily separate and curl up each lash for instant length, volume, and curl', 'Use the sculpting comb brush to precisely and easily separate and curl up each lash for instant length, volume, and curl', 3.975, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZEE935C2CCA2F8E2F315EZ/45/_/1782298164/fd7073da-d1ba-479d-9efe-3e13719270a0.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZEE935C2CCA2F8E2F315EZ/45/_/1782298164/0501bf82-f5b6-4404-9051-98310335fbb6.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZEE935C2CCA2F8E2F315EZ/45/_/1782298219/3671580a-40b1-4a15-b3fd-d19128ad88fb.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZEE935C2CCA2F8E2F315EZ/45/_/1782298219/f823818f-3924-4e9f-b38a-0d0ab1e6a995.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'l-oreal-paris'), 4.6, 86, 0, true, false, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('Twist Up The Volume Mascara – 001 –Ultra Black', 'twist-up-the-volume-mascara-001-ultra-black', '"Take lashes to new heights with new Twist Up The Volume Mascara – the only Bourjois mascara with a unique 2-in-1 brush that combines lengthening power and volumizing intensity. It glides smoothly onto lashes and features a flexible film formula that delivers ultra-buildable length and volume. The lash-caring formulation contains collagen and keratin and has a weightless feel for super-comfortable wear. The Extreme Black shade is loaded with intense pigments for a high-glam lash look. Ready to play with make up? Start having fun with color and add a playful “je ne sais quoi” to your style! Bourjois gifts every woman the Parisian secret of effortless but chic beauty to create looks for face and nails with a Parisian twist."', '"Take lashes to new heights with new Twist Up The Volume Mascara – the only Bourjois mascara with a unique 2-in-1 brush that combines length…', 6.5, NULL, 'BHD', '["https://f.nooncdn.com/p/v1668417406/N52913390A_1.jpg?width=1200","https://f.nooncdn.com/p/v1668417406/N52913390A_3.jpg?width=1200","https://f.nooncdn.com/p/v1668417405/N52913390A_4.jpg?width=1200","https://f.nooncdn.com/p/v1654680066/N52913390A_5.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'bourjois-paris'), 4.3, 2482, 0, true, false, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('Oil Resistant Mascara for Volum Lashes', 'oil-resistant-mascara-for-volum-lashes', 'Mascara is a makeup essential that enhances the beauty of the eyes and gives lashes thickness and length. Among the options available on the market, Pink Flash Oil-Resistant Mascara stands out, providing a unique experience for thicker, longer-lasting lashes. Benefits: Oil-resistant: Long-lasting and unaffected by the skin''s natural oils. Lash Thickening: Delivers double-density results thanks to its effective formula. Long-lasting: Lasts up to 12 hours without the need to reapply makeup. Easy to Remove: Removes easily without damaging lashes.', 'Mascara is a makeup essential that enhances the beauty of the eyes and gives lashes thickness and length.', 1.446, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZB18687C9C4000D17B7CCZ/45/1745060772/512ad34e-83ec-48a2-b6d9-ac8dc40f2e3c.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZB18687C9C4000D17B7CCZ/45/1745061715/33915fd9-9adf-43ef-9731-eb5e8e593d52.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'pink-flash'), 4.3, 43, 0, true, false, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('Leopard Print Black Mascara, 24H Waterproof Smudge-Proof Volumizing Mascara, Curling & Lengthening, Clump-Free Long Lasting Eye Makeup', 'leopard-print-black-mascara-24h-waterproof-smudge-proof-volumizing-mas', 'Tired of mascara that smudges, flattens, or fails to deliver volume in the Middle East''s extreme heat? This luxury leopard print volumizing mascara, custom-made for Middle Eastern women, is your ultimate eye makeup savior! We understand the ultimate pursuit of eye makeup by Middle Eastern women, so we''ve created an all-in-one mascara that combines volume, long wear, ease of use, and gentleness . The highly pigmented jet-black formula, paired with a 360° spiral brush, coats every lash evenly from root to tip, delivering 3-in-1 results: lengthening, volumizing, and curling in one swipe. Instantly create deep, three-dimensional big eyes, perfectly suited to the deep eye shapes of Middle Eastern women, suitable for both natural daily makeup and bold party looks. The smooth, non-sticky formula is beginner-friendly, with a simple swipe for separated, clump-free lashes, no spidery effect. Even makeup novices can achieve professional results effortlessly. With a superior waterproof and sweatproof formula, it withstands the Middle East''s 35°C+ high temperatures, resisting sweat, swimming, and long wear without smudging or flaking. 24-hour long-lasting curl keeps your makeup flawless from morning to night, eliminating panda eye embarrassment. We also prioritize easy and gentle removal. No need for harsh makeup removers; it easily comes off with warm water and regular facial cleanser, without pulling or damaging delicate lashes. Gentle and non-irritating, it''s safe for sensitive eyes and contact lens wearers. The trendy gold leopard print tube combines style and function, not just a beauty tool but a fashion accessory. Portable for on-the-go touch-ups, it helps you unleash your feline charm, making you the center of attention at work, dates, and parties, and conquering every urban highlight moment with bold, wild lashes!', 'Tired of mascara that smudges, flattens, or fails to deliver volume in the Middle East''s extreme heat? This luxury leopard print volumizing…', 2.59, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z68A9CFFD4497C563C2B8Z/45/_/1783936583/d9708374-8f8c-4a8d-9a76-8508188af554.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z68A9CFFD4497C563C2B8Z/45/_/1779090402/46259f7c-6aa7-404c-9608-6250e0310eb3.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z68A9CFFD4497C563C2B8Z/45/_/1779090401/0c6d1c94-bca3-4748-b981-79d30b64d830.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z68A9CFFD4497C563C2B8Z/45/_/1779090401/de74a4c6-bb68-48ea-8e26-50ff50759528.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'zmdream'), 5, 6, 0, true, true, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('LASH SENSATIONAL SKY HIGH MASCARA, BLACK, 36H, LENGTHENING, VOLUMIZING, +2MM LENGTH ON ASIAN LASHES Black', 'lash-sensational-sky-high-mascara-black-36h-lengthening-volumizing-2mm', 'Maybelline''s Lash Sensational Sky High mascara delivers full volume and limitless length. Exclusive Flex Tower mascara brush bends to volumize and extend every single lash from root to tip. Washable mascara formula infused with bamboo extract and fibers for long, full and lightweight lashes, that don''t flake or smudge.', 'Maybelline''s Lash Sensational Sky High mascara delivers full volume and limitless length.', 3.495, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N52474852A/45/_/1744023308/9203a4f1-8660-4213-84d7-7b8177081acf.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N52474852A/45/_/1744023323/353dfe2f-ace2-4da7-9927-a3d9e2c22c35.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N52474852A/45/_/1744023310/6372a903-6c3c-4564-b6ec-e0e7365fbbd5.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N52474852A/45/_/1744023312/58745ff0-497b-455c-a5e3-f30dad618360.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'maybelline-new-york'), 3.4, 5844, 0, true, false, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('Telescopic Lift Mascara', 'telescopic-lift-mascara', 'Lift your lashes to the next level with L''Oreal Paris Telescopic Lift Mascara. Get instant lash lift, volume and up to +5MM Visible Length for up to 36 hour wear. L’Oreal Paris’s Exclusive load and lift double-hook bristle brush catches and charges every lash. Easy to apply! 9.4 ml.', 'Lift your lashes to the next level with L''Oreal Paris Telescopic Lift Mascara.', 3.595, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z59D7226FF324E5FE4638Z/45/_/1690548301/8d2765bf-bafd-42fc-badb-f600dd2c663b.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z59D7226FF324E5FE4638Z/45/_/1690548302/f0a34ebc-d5c3-4f21-b6a6-2e7f228edbb4.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z59D7226FF324E5FE4638Z/45/_/1690548304/4611a0c2-f37b-49bb-b5ce-0ac365dfbe7b.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z59D7226FF324E5FE4638Z/45/_/1690548303/5bd08273-6f46-4960-b134-20dc02f85639.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'l-oreal-paris'), 4.3, 809, 0, true, false, true, ARRAY['makeup', 'eyes', 'mascara']::text[]),
  ('Romantic key Bright 42Colour Palette', 'romantic-key-bright-42colour-palette', 'Online shopping for romantic key. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy Free Returns ✓ Cash on Delivery. Shop Now', 'Online shopping for romantic key. Trusted Shipping to Riyadh, Jeddah and all KSA ✓ Great Prices ✓ Secure Shopping ✓ 100% Contactless ✓ Easy…', 3.6, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z659BF7C23AA1083E31CFZ/45/1759044374/63038d48-fed2-44f1-90ef-a854cb398ce4.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z659BF7C23AA1083E31CFZ/45/1759044372/355f24ed-ba96-4aef-9f60-ba01fa3912b0.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z659BF7C23AA1083E31CFZ/45/1759044373/61424491-6829-4b30-8c15-23d22209c45a.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'romantic-key'), 4.7, 47, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('Palette 00 Light and Glitter Garden 7.5g', 'palette-00-light-and-glitter-garden-7-5g', 'Discover the magic of color with the Room & Secret Gardens Eyeshadow Palette, which combines elegance and softness in 10 perfect matte and shimmer shades. Features: A wide range of colors to suit all skin tones. A finely milled formula provides smooth application and long-lasting wear. Shining colors without blemishing thanks to ultra-fine glitter particles. Ideal for creating multiple day and evening looks with ease. One palette gives you everything you need for a captivating eye look that lasts all day.', 'Discover the magic of color with the Room & Secret Gardens Eyeshadow Palette, which combines elegance and softness in 10 perfect matte and s…', 9.404, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z8839C9508BDDBC639BE4Z/45/1749022258/1ada200a-48b2-4657-8a1b-e2253746d9d2.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z8839C9508BDDBC639BE4Z/45/1749022259/ab8d361e-e77f-4ce2-abe7-7ea13d863abf.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'rom-nd'), 4.3, 7, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('Eyeshadow Palette PF-E15', 'eyeshadow-palette-pf-e15', 'Pink Flash Multi-Color Liquid Eyeshadow is an innovative product designed to provide a shimmering, eye-catching effect to your eye makeup. It features an easy-to-apply liquid formula that allows you to achieve a long-lasting, radiant look. Features: Shining effect: Gives the eyes a striking sparkle, enhancing their appeal. Easy application: Thanks to its liquid formula, it can be applied easily without caking. Long-lasting: Ensures long-lasting color and shine without the need for reapplication. How to use: Prep the eyelids: Start by applying an eye primer to ensure the shadows stay in place. Apply the shadows: Using the built-in brush or your fingertips, apply an appropriate amount of liquid shadow to the eyelid. Blend the color: Gently blend the edges for a consistent, natural look.', 'Pink Flash Multi-Color Liquid Eyeshadow is an innovative product designed to provide a shimmering, eye-catching effect to your eye makeup.', 2.893, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZF55819305531AAC450F4Z/45/1745135839/89109efd-7491-4753-8e67-91f07b7e81aa.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZF55819305531AAC450F4Z/45/1745135884/47407cbe-03ed-4656-9987-0d99c57e9344.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZF55819305531AAC450F4Z/45/1745135931/1050bf2e-9780-4cac-b52f-d290140914f1.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'pink-flash'), 4.6, 17, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('Eye Palette, Backstage Is The Palette Of 9 Long-Wear Eyeshadows, 002 Cool Neutrals', 'eye-palette-backstage-is-the-palette-of-9-long-wear-eyeshadows-002-coo', 'Dior has created its first professional makeup line, a collection of makeup artist essentials, inspired by the energy backstage at the runway shows. Shades to suit all skin tones in exclusive* and buildable textures.', 'Dior has created its first professional makeup line, a collection of makeup artist essentials, inspired by the energy backstage at the runwa…', 11, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z592AC2683DC74B0F92B4Z/45/_/1779705237/f8f1df34-3ffd-4fd1-a842-15660a8e35e9.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z592AC2683DC74B0F92B4Z/45/_/1779705237/af0284a6-5529-4491-b648-feff5c4be62e.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z592AC2683DC74B0F92B4Z/45/_/1779705237/ce488930-d960-418a-8161-2398aba85320.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z592AC2683DC74B0F92B4Z/45/_/1779705237/8fea2209-6adb-4631-a163-bad1627f595d.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'dior'), 3.6, 23, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('Eye Palette, Backstage Is The Palette Of 9 Long-Wear Eyeshadows, 010 Copper Essentials', 'eye-palette-backstage-is-the-palette-of-9-long-wear-eyeshadows-010-cop', 'Dior Backstage Eye Palette is the palette of 9 long-wear eyeshadows designed by Peter Philips, Creative and Image Director for Dior Makeup. This eye makeup essential from the House of Dior allows you to achieve many makeup looks for eyes that are enhanced with matte, pearlescent, metallic, holographic or glittery shades, depending on the palette used.', 'Dior Backstage Eye Palette is the palette of 9 long-wear eyeshadows designed by Peter Philips, Creative and Image Director for Dior Makeup.', 9.2, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z9FDFED5C9D4901E50C2EZ/45/_/1779706509/86ccce54-b4ca-4a00-9cbc-3d8eb037f77a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z9FDFED5C9D4901E50C2EZ/45/_/1779706509/ca11160a-44c2-4602-b02a-ccb3c9485051.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'dior'), 3.6, 23, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('X Priyanka Chopra Jonas Eyeshadow Stick, Limited Edition - 001 - Berry Bloom, 1.65 g', 'x-priyanka-chopra-jonas-eyeshadow-stick-limited-edition-001-berry-bloo', 'Live Life in Full Bloom with the limited-edition Priyanka Chopra Jonas Full Bloom Colour Collection. • The colour of this eyeshadow stick pencil offers great pigmentation and adds full colour in one swipe with a soft & silky feel. • Perfect for on-the-go, the vegan eyeshadow lasts all day long, goes on easily & blends effortlessly with no base, brush or touch-ups needed. Experience even payoff and a crease-resistant finish with no flaking or smudging. • Available in 6 effortlessly blendable shimmery & creamy matte eyeshadow shades, the pencil lets you create a bold eye expression in a shade that suits your mood and complexion. • Explore the whole collection with highly pigmented, unmissable and vibrant colours for eyes, lips and nails.', 'Live Life in Full Bloom with the limited-edition Priyanka Chopra Jonas Full Bloom Colour Collection.', 4.3, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z4E72244F6AF4190C8988Z/45/1750255423/6c27504b-4f9d-48e5-86b2-7fd1f184741d.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4E72244F6AF4190C8988Z/45/1750255423/44d6cc25-91a1-4db2-969d-c315b4f86f50.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4E72244F6AF4190C8988Z/45/1750255423/ff7e7f52-fa1b-4a86-9fb0-b548e0ad4e9a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4E72244F6AF4190C8988Z/45/1750255423/a7adaca0-9959-4567-97fd-eadbd65b4a37.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'max-factor'), 5, 1, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('The Secret Garden 10-Color Eyeshadow Palette 02 Mahogany Garden', 'the-secret-garden-10-color-eyeshadow-palette-02-mahogany-garden', 'Discover the magic of color with the Room & Secret Gardens Eyeshadow Palette, which combines elegance and softness in 10 perfect matte and shimmer shades. Features: A wide range of colors to suit all skin tones. A finely milled formula provides smooth application and long-lasting wear. Shining colors without blemishing thanks to ultra-fine glitter particles. Ideal for creating multiple day and evening looks with ease. One palette gives you everything you need for a captivating eye look that lasts all day.', 'Discover the magic of color with the Room & Secret Gardens Eyeshadow Palette, which combines elegance and softness in 10 perfect matte and s…', 9.404, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z9B3588E44F351A239A3AZ/45/1749028453/7ee6d940-7992-480b-b362-f0d09f594b11.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z9B3588E44F351A239A3AZ/45/1749028467/4de19221-55ed-46b4-a4c5-b044b1b9ad9b.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'rom-nd'), 5, 3, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('Multi Color Liquid Eyeshadow', 'multi-color-liquid-eyeshadow', 'Pink Flash Multi-Color Duo Liquid Eyeshadow is an innovative product designed to deliver a shimmering and eye-catching effect to your eye makeup. Thanks to its liquid formula, it allows you to achieve a long-lasting, radiant look. Features: Shining effect: Gives the eyes a striking sparkle, enhancing their appeal. Easy application: Thanks to its liquid formula, it can be applied easily without caking. Long-lasting: Ensures long-lasting color and shine without the need for reapplication. How to use: Prep the eyelids: Start by applying an eye primer to ensure the shadows stay put. Apply the shadows: Using the built-in brush or your fingertips, apply an appropriate amount of liquid shadows to the eyelid. Blend the color: Gently blend the edges for a natural, even look.', 'Pink Flash Multi-Color Duo Liquid Eyeshadow is an innovative product designed to deliver a shimmering and eye-catching effect to your eye ma…', 1.736, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z22A72361666006BB3498Z/45/1745135310/c722724a-0edc-4e5b-ad46-2da3e2e2731a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z22A72361666006BB3498Z/45/1745135399/f67ab818-adc0-4124-b9f7-616215460e35.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z22A72361666006BB3498Z/45/1745135450/e963bea3-5d30-4c25-99f2-a870ff74ef6f.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z22A72361666006BB3498Z/45/1745135502/a2c9840c-c4d1-466c-ae20-f3d345459c8a.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'pink-flash'), 5, 6, 0, true, true, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('42 COLOR EYESHADOW PALETTE', '42-color-eyeshadow-palette', 'It consists of an amazing collection of colors and textures and everything you need in one palette. Ideal for professional makeup, bridal makeup, light-based makeup. Highly pigmented formula that lasts all day without flaking. Multicolor bright, warm, fashionable, constant', 'It consists of an amazing collection of colors and textures and everything you need in one palette.', 3.495, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z12E82D990BBBC880BF86Z/45/_/1772580530/8b59bf7e-2942-4828-8b0c-1a634ef75ec0.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z12E82D990BBBC880BF86Z/45/_/1772580530/9fa8a137-b148-47fa-b01c-11135d7c07ac.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'loveme-beauty'), 4.5, 39, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('25 Color Eye Shadow Palette - Zigzag Edition', '25-color-eye-shadow-palette-zigzag-edition', 'Unleash your creativity with the Zigzag Edition 25 Color Eye Shadow Palette. This dynamic palette features a vibrant collection of 25 highly pigmented shades, from bold primary colors to versatile neutrals. Each shade is designed to blend seamlessly, allowing you to create a wide range of looks, from everyday chic to dramatic and bold. The silky, smooth texture ensures effortless application and long-lasting wear. Whether you’re looking for a subtle enhancement or a striking standout look, this palette has everything you need. Encased in a stylish zigzag-patterned packaging, it’s a chic addition to any makeup collection.', 'Unleash your creativity with the Zigzag Edition 25 Color Eye Shadow Palette.', 2.8, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z6CB7B8F26AC401AC59EBZ/45/_/1723653268/dc724cae-d0e9-4a79-b814-02203331d268.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6CB7B8F26AC401AC59EBZ/45/_/1723653267/3dbe9564-e27d-443a-bdab-90c527d38da0.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6CB7B8F26AC401AC59EBZ/45/_/1722155484/89a53ee4-5962-4c28-afa3-efecc439ba5a.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6CB7B8F26AC401AC59EBZ/45/_/1722155485/3c40db6b-a17e-4c60-a699-b08ef3764e77.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'anatasia'), 4.1, 181, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('25 Color Eye Shadow Palette - Pastel Edition', '25-color-eye-shadow-palette-pastel-edition', 'Elevate your makeup game with the Pastel Edition 25 Color Eye Shadow Palette. This exquisite palette features a stunning array of 25 highly pigmented shades, including soft pastels and bold, vibrant colors. Designed to blend seamlessly, these shades allow you to create a variety of looks, from everyday elegance to bold and dramatic. The smooth, silky texture ensures effortless application and long-lasting wear. Whether you''re aiming for a subtle, natural look or a striking, standout appearance, this palette is your perfect companion. Encased in a chic, pastel-themed packaging, it''s a stylish addition to any makeup collection.', 'Elevate your makeup game with the Pastel Edition 25 Color Eye Shadow Palette.', 2.2, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZA0F777811432E395DAE0Z/45/_/1723653292/294ccd38-7df8-4039-bfbd-548f3f5fc773.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZA0F777811432E395DAE0Z/45/_/1729410498/53750e28-ff3a-40ed-8e36-be337b6eea68.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'anatasia'), 4.1, 181, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('18 Color Eyeshadow Palette Multicolour', '18-color-eyeshadow-palette-multicolour', 'Pro-level palette packed with 16 high-performance eyeshadows in a rainbow of tone-inspired shades. Mix of velvety-rich, complimentary colors in mesmerizing finishes. Different color for different look high quality ingredients with silky shine color', 'Pro-level palette packed with 16 high-performance eyeshadows in a rainbow of tone-inspired shades.', 4.1, NULL, 'BHD', '["https://f.nooncdn.com/p/v1564552066/N28332782A_1.jpg?width=1200","https://f.nooncdn.com/p/v1564552064/N28332782A_2.jpg?width=1200","https://f.nooncdn.com/p/v1564552065/N28332782A_3.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'eyes'), (select id from public.brands where slug = 'make-over-22'), 4.7, 23, 0, true, false, true, ARRAY['makeup', 'eyes', 'eye', 'shadow']::text[]),
  ('Fat Oil Lip Drip Moisturizing Shiny Vegan Tinted Lip Gloss Non-Sticky Finish 12H Hydration - Follow Back', 'fat-oil-lip-drip-moisturizing-shiny-vegan-tinted-lip-gloss-non-sticky', 'Say hello to Fat Oil, our first lip drip of its kind. Lips drippin'' with FAT perks. FAT SHINE. FAT CARE. FAT 12 HR HYDRATION. The fat family is getting FATTER! Wear it alone or layer it over lip liner or lipstick for added color and shine. Get ready for 6 new CREAMY shades. Fat Oil has a high shine finish with comfortable wear and a non-sticky texture. Packed with FAT goodness to keep your lips dripping using cloudberry oil, raspberry oil and squalane. The best part? You are one swipe away from FAT perks. Vegan. Cruelty-free.', 'Say hello to Fat Oil, our first lip drip of its kind. Lips drippin'' with FAT perks. FAT SHINE. FAT CARE. FAT 12 HR HYDRATION.', 5.645, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z0EC1E2241BC677136377Z/45/1764762061/b7485700-39bc-4d2c-86c1-a05f6470b084.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0EC1E2241BC677136377Z/45/_/1739784036/ca5a4626-a7da-4b81-a855-705ab6f3f020.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0EC1E2241BC677136377Z/45/_/1739784035/c7e5e9a3-50a1-4d54-a8f9-bbf24653640e.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z0EC1E2241BC677136377Z/45/_/1739784037/e2da90f2-f0bb-4f20-9ea5-f146fe98bc93.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'lips'), (select id from public.brands where slug = 'nyx-professional-makeup'), 4.6, 4915, 0, true, false, true, ARRAY['makeup', 'lips', 'lip', 'glosses']::text[]),
  ('Summer Mini Fridays Lip Butter Balm Set for Instant Moisture, Shine and Hydration, Pack of 4', 'summer-mini-fridays-lip-butter-balm-set-for-instant-moisture-shine-and', 'Mini and Portable: Each lip balm is 5g, making it perfect for on-the-go use, whether you''re traveling, at the office, or out and about.. Natural Ingredients: Infused with effective, hydrating natural ingredients such as Vitamin E and plant oils, deeply moisturizing and repairing dry, chapped lips, leaving them soft and smooth.. Four Delightful Scents: The set includes four different scents and flavors, ranging from fresh fruit notes to mild floral aromas, offering a variety of options to suit your preferences.. Non-Greasy: The non-greasy formula ensures your lips feel comfortable and natural without any sticky residue, keeping them moisturized for hours.. Limited Edition: This mini set is a limited edition release, making it a great gift for friends and family or a special addition to your own collection.', 'Mini and Portable: Each lip balm is 5g, making it perfect for on-the-go use, whether you''re traveling, at the office, or out and about..', 4.29, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/ZADDC0D67245F44D72F77Z/45/_/1783152333/d35aa4f2-60da-45dd-a287-53693be79eba.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZADDC0D67245F44D72F77Z/45/_/1783152333/6d608d6c-f85c-45e8-8c9e-2023d914ea9c.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZADDC0D67245F44D72F77Z/45/_/1783151641/f23a5d5a-ba0e-440e-82ff-c8edcc383255.jpg?width=1200","https://f.nooncdn.com/p/pzsku/ZADDC0D67245F44D72F77Z/45/_/1783151642/367efe00-5073-4b7f-a611-0b957dadf922.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'lips'), (select id from public.brands where slug = 'summer-fridays'), 3.8, 13, 0, true, false, true, ARRAY['makeup', 'lips', 'lip', 'glosses']::text[]),
  ('Glossy Mirror Lip Tint 01 Trendy Celebrity Peach | Peach Nude High-Shine Finish, Lightweight Non-Sticky Lip Color', 'glossy-mirror-lip-tint-01-trendy-celebrity-peach-peach-nude-high-shine', 'The Glossy Mirror Lip Tint in 01 Trendy Celebrity Peach features a soft and flattering peachy nude tone that is perfect for everyday wear. The shade gives the lips a naturally polished look while adding a fresh touch of color without appearing too bold. It is an easy choice for daily makeup, office looks, casual outings, and soft glam styles. This lip tint combines a juicy mirror-like shine with a smooth, lightweight texture for comfortable wear. It glides on evenly and helps create a fuller-looking lip appearance with a glossy, glass-like finish. Apply a thin layer for a soft natural nude-peach look, or build it up for a richer and more defined result. The finish looks elegant, fresh, and modern, making it suitable for a wide range of makeup styles. The lip-hugging applicator helps distribute the product evenly and offers better control when outlining and filling the lips. With its wearable color, glossy finish, and comfortable non-heavy feel, Shade 01 Trendy Celebrity Peach is a versatile lip tint designed for customers who want shine, softness, and everyday elegance in one product.', 'The Glossy Mirror Lip Tint in 01 Trendy Celebrity Peach features a soft and flattering peachy nude tone that is perfect for everyday wear.', 2.49, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z4673EC19B1A9648B4797Z/45/_/1780908863/5dc82f11-0a89-4f6f-9456-80b16bb35b43.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4673EC19B1A9648B4797Z/45/_/1780908881/1422f0e4-1b75-4ec9-bc86-5009100abfbf.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4673EC19B1A9648B4797Z/45/_/1780908659/4e023999-22ab-4495-a9b7-c6048e9b7d5f.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z4673EC19B1A9648B4797Z/45/_/1780908659/6f7dfdb9-1c58-4b60-a683-1911ec074e9f.jpg?width=1200"]'::jsonb, (select id from public.categories wh