  ('Naturals Plant Series – Argan Speedy Hair Color Shampoo (Dark Brown) 400 ml', 'naturals-plant-series-argan-speedy-hair-color-shampoo-dark-brown-400-m', 'How to use hair dye shampoo. 1- Wear the included gloves. 2-Put a little shampoo on the palms of your hands. 3- Mix the shampoo on the palms of your hands. 4- Massage the shampoo into your hair and distribute it evenly throughout the hair. 5- Leave the shampoo on your hair for 5 to 10 minutes. 6-Then wash your hair well with water.', 'How to use hair dye shampoo. 1- Wear the included gloves. 2-Put a little shampoo on the palms of your hands.', 2.55, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z30764D735D2ACE19B503Z/45/_/1779261982/5bd3a3f2-0da7-4f89-9e8e-e10e85c95fc0.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z30764D735D2ACE19B503Z/45/_/1779261987/1f697ac2-75a6-4999-8e79-76b29cc1cf71.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z30764D735D2ACE19B503Z/45/_/1779262005/24d29ff5-82f0-4542-af67-4f8e48bdd903.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z30764D735D2ACE19B503Z/45/_/1779262131/39a6a1f6-61bc-439f-8ba7-c5dddee5a7b5.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'hair-color'), (select id from public.brands where slug = 'naturals'), 3.9, 488, 0, true, false, true, ARRAY['hair', 'care', 'color', 'chemical', 'dyes']::text[]),
