  ('Lamsat Harir Gift Set (1 x EDP 100ml, 1 x Perfumed Body Spray 200ml)', 'lamsat-harir-gift-set-1-x-edp-100ml-1-x-perfumed-body-spray-200ml', 'Crafted bottle and sophisticated pump delivers great coverage. A deep concentration for a rich and long-lasting scent. Beautiful packaging ideal for gifting', 'Crafted bottle and sophisticated pump delivers great coverage. A deep concentration for a rich and long-lasting scent.', 5.155, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N21150996A/45/_/1764242142/cc56e88c-267c-4408-b793-46c1f5304a73.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N21150996A/45/_/1764242142/4a4ba74f-a0bf-4e98-9c63-a16bf6223eb3.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N21150996A/45/_/1764242143/a960706a-c3e1-46eb-a17f-9a2bddbdae30.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'fragrance-gift-sets'), (select id from public.brands where slug = 'arabiyat'), 4.5, 1561, 0, true, false, true, ARRAY['fragrance', 'gift', 'sets']::text[]),
  ('Lattafa 2-Piece Pure Musk Gift Set (1 Khalish Musk EDP 100ml, 1 Deo Spray 75ml', 'lattafa-2-piece-pure-musk-gift-set-1-khalish-musk-edp-100ml-1-deo-spra', 'A modern, young & vibrant interpretation of addiction. Long lasting and irresistable, it truly is a delight to wear. Vibrant, magnetic and charismatic approach tagged with the fragrance. Packaging may vary', 'A modern, young & vibrant interpretation of addiction. Long lasting and irresistable, it truly is a delight to wear.', 4.5, NULL, 'BHD', '["https://f.nooncdn.com/p/pnsku/N20791287A/45/_/1764241835/cbe5d273-9ca3-4078-a2e0-fe6e7ae9caa4.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N20791287A/45/_/1764241837/39c52737-46a0-4d8f-bd98-39f8f63d581b.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N20791287A/45/_/1764241838/24543e9d-e339-4743-970e-b4b8fde7659b.jpg?width=1200","https://f.nooncdn.com/p/pnsku/N20791287A/45/_/1764241836/65f27799-332e-42db-aed3-c590271d0c78.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'fragrance-gift-sets'), (select id from public.brands where slug = 'lattafa'), 4.2, 1099, 0, true, false, true, ARRAY['fragrance', 'gift', 'sets']::text[]),
  ('Sacrifice For Her Gift Box', 'sacrifice-for-her-gift-box', 'Sacrifice by Ajmal personifies kindness, love, and an undisturbed beauty that captivates all who behold her. Her ethereal presence exudes an undeniable strength and unwavering confidence, inspiring us to meticulously blend the tenacity of blooming florals with the invigorating freshness of aqueous notes, ultimately grounded by the timeless allure of amber and musk. This enchanting fragrance serves as a steadfast guardian, preserving your essence and ensuring that your glorious spirit never wanes or fades away. It stands as a perpetual homage to her profound influence and everlasting legacy.', 'Sacrifice by Ajmal personifies kindness, love, and an undisturbed beauty that captivates all who behold her.', 12.345, NULL, 'BHD', '["https://f.nooncdn.com/p/pzsku/Z6253663F1809EB710F9FZ/45/1745313244/f4ee6d4a-c1f7-443c-b6aa-1ad8f97a4084.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6253663F1809EB710F9FZ/45/1745313243/1af024e8-79ba-4563-8909-087a69ece065.jpg?width=1200","https://f.nooncdn.com/p/pzsku/Z6253663F1809EB710F9FZ/45/1745324464/b4b9e16d-4b9e-45d2-acd6-c1f353c781a3.jpg?width=1200"]'::jsonb, (select id from public.categories where slug = 'fragrance-gift-sets'), (select id from public.brands where slug = 'ajmal'), 4.6, 184, 0, true, false, true, ARRAY['fragrance', 'gift', 'sets']::text[]),
